func permute(nums []int) [][]int {
    res := [][]int{}
    used := make([]bool, len(nums))
    path := []int{}

    var backtrack func()
    backtrack = func() {
        // 终止条件：路径长度等于数组长度
        if len(path) == len(nums) {
            tmp := make([]int, len(path))
            copy(tmp, path)
            res = append(res, tmp)
            return
        }

        for i := 0; i < len(nums); i++ {
            if used[i] {
                continue // 剪枝：跳过已使用的元素
            }

            // 做选择
            used[i] = true
            path = append(path, nums[i])

            // 进入下一层决策树
            backtrack()

            // 撤销选择
            path = path[:len(path)-1]
            used[i] = false
        }
    }

    backtrack()
    return res
}

class Solution:
    def permute(self, nums: List[int]) -> List[List[int]]:
        res = []
        used = [False] * len(nums)

        def backtrack(path):
            if len(path) == len(nums):
                res.append(path[:])
                return
            for i in range(len(nums)):
                if not used[i]:
                    used[i] = True
                    path.append(nums[i])
                    backtrack(path)
                    path.pop()
                    used[i] = False

        backtrack([])
        return res

class Solution {
    public List<List<Integer>> permute(int[] nums) {
        List<List<Integer>> res = new ArrayList<>();
        boolean[] used = new boolean[nums.length];
        backtrack(nums, res, new ArrayList<>(), used);
        return res;
    }

    private void backtrack(int[] nums, List<List<Integer>> res, List<Integer> path, boolean[] used) {
        if (path.size() == nums.length) {
            res.add(new ArrayList<>(path));
            return;
        }
        for (int i = 0; i < nums.length; i++) {
            if (!used[i]) {
                used[i] = true;
                path.add(nums[i]);
                backtrack(nums, res, path, used);
                path.remove(path.size() - 1);
                used[i] = false;
            }
        }
    }
}

func subsets(nums []int) [][]int {
    res := [][]int{}
    path := []int{}

    var backtrack func(start int)
    backtrack = func(start int) {
        // 每个节点都是有效解
        tmp := make([]int, len(path))
        copy(tmp, path)
        res = append(res, tmp)

        for i := start; i < len(nums); i++ {
            path = append(path, nums[i])     // 做出选择
            backtrack(i + 1)                  // 限制选择范围
            path = path[:len(path)-1]         // 撤销选择
        }
    }

    backtrack(0)
    return res
}

class Solution:
    def subsets(self, nums: List[int]) -> List[List[int]]:
        res = []

        def backtrack(start, path):
            res.append(path[:])
            for i in range(start, len(nums)):
                path.append(nums[i])
                backtrack(i + 1, path)
                path.pop()

        backtrack(0, [])
        return res

class Solution {
    public List<List<Integer>> subsets(int[] nums) {
        List<List<Integer>> res = new ArrayList<>();
        backtrack(nums, res, new ArrayList<>(), 0);
        return res;
    }

    private void backtrack(int[] nums, List<List<Integer>> res, List<Integer> path, int start) {
        res.add(new ArrayList<>(path));
        for (int i = start; i < nums.length; i++) {
            path.add(nums[i]);
            backtrack(nums, res, path, i + 1);
            path.remove(path.size() - 1);
        }
    }
}

func letterCombinations(digits string) []string {
    if len(digits) == 0 {
        return []string{}
    }

    // 建立数字到字母的映射
    letterMap := []string{
        "",     // 0
        "",     // 1
        "abc",  // 2
        "def",  // 3
        "ghi",  // 4
        "jkl",  // 5
        "mno",  // 6
        "pqrs", // 7
        "tuv",  // 8
        "wxyz", // 9
    }

    res := []string{}
    var sb strings.Builder

    var backtrack func(index int)
    backtrack = func(index int) {
        // 到达叶子节点，收集结果
        if index == len(digits) {
            res = append(res, sb.String())
            return
        }

        // 当前数字对应的所有可能字母
        letters := letterMap[digits[index]-'0']
        for _, letter := range letters {
            sb.WriteByte(byte(letter))
            backtrack(index + 1)
            sbStr := sb.String()
            sb.Reset()
            sb.WriteString(sbStr[:len(sbStr)-1])
        }
    }

    backtrack(0)
    return res
}

class Solution:
    def letterCombinations(self, digits: str) -> List[str]:
        if not digits:
            return []

        mapping = {
            '2': 'abc', '3': 'def', '4': 'ghi', '5': 'jkl',
            '6': 'mno', '7': 'pqrs', '8': 'tuv', '9': 'wxyz'
        }

        res = []

        def backtrack(index, path):
            if index == len(digits):
                res.append(''.join(path))
                return
            for c in mapping[digits[index]]:
                path.append(c)
                backtrack(index + 1, path)
                path.pop()

        backtrack(0, [])
        return res

class Solution {
    public List<String> letterCombinations(String digits) {
        List<String> res = new ArrayList<>();
        if (digits.length() == 0) return res;

        String[] mapping = {"", "", "abc", "def", "ghi", "jkl", "mno", "pqrs", "tuv", "wxyz"};
        backtrack(digits, res, mapping, new StringBuilder(), 0);
        return res;
    }

    private void backtrack(String digits, List<String> res, String[] mapping, StringBuilder path, int index) {
        if (index == digits.length()) {
            res.add(path.toString());
            return;
        }
        String letters = mapping[digits.charAt(index) - '0'];
        for (int i = 0; i < letters.length(); i++) {
            path.append(letters.charAt(i));
            backtrack(digits, res, mapping, path, index + 1);
            path.deleteCharAt(path.length() - 1);
        }
    }
}

func combinationSum(candidates []int, target int) [][]int {
    result := [][]int{}
    path := []int{}

    sort.Ints(candidates) // 关键第一步：排序为剪枝做准备

    var backtrack func(remain, start int)
    backtrack = func(remain, start int) {
        if remain < 0 {
            return // 超额直接返回
        }
        if remain == 0 { // 找到合法组合
            tmp := make([]int, len(path))
            copy(tmp, path)
            result = append(result, tmp)
            return
        }

        for i := start; i < len(candidates); i++ {
            if candidates[i] > remain {
                break // 剪枝：提前终止无效分支
            }

            path = append(path, candidates[i]) // 选择当前元素
            backtrack(remain-candidates[i], i) // 关键：允许重复选择
            path = path[:len(path)-1]          // 撤销选择（回溯）
        }
    }

    backtrack(target, 0)
    return result
}

class Solution:
    def combinationSum(self, candidates: List[int], target: int) -> List[List[int]]:
        res = []
        def backtrack(start, path, remaining):
            if remaining == 0:
                res.append(path[:])
                return
            if remaining < 0:
                return
            for i in range(start, len(candidates)):
                path.append(candidates[i])
                backtrack(i, path, remaining - candidates[i])
                path.pop()
        backtrack(0, [], target)
        return res

class Solution {
    public List<List<Integer>> combinationSum(int[] candidates, int target) {
        List<List<Integer>> res = new ArrayList<>();
        backtrack(candidates, target, res, new ArrayList<>(), 0, 0);
        return res;
    }
    private void backtrack(int[] candidates, int target, List<List<Integer>> res, List<Integer> path, int start, int sum) {
        if (sum == target) {
            res.add(new ArrayList<>(path));
            return;
        }
        if (sum > target) return;
        for (int i = start; i < candidates.length; i++) {
            path.add(candidates[i]);
            backtrack(candidates, target, res, path, i, sum + candidates[i]);
            path.remove(path.size() - 1);
        }
    }
}

func generateParenthesis(n int) []string {
    result := []string{}

    var backtrack func(current string, open, close int)
    backtrack = func(current string, open, close int) {
        // 找到有效组合
        if len(current) == n*2 {
            result = append(result, current)
            return
        }

        // 可以添加左括号的条件：未使用的左括号数量大于0
        if open < n {
            backtrack(current+"(", open+1, close)
        }

        // 可以添加右括号的条件：已使用的右括号少于左括号
        if close < open {
            backtrack(current+")", open, close+1)
        }
    }

    backtrack("", 0, 0)
    return result
}

class Solution:
    def generateParenthesis(self, n: int) -> List[str]:
        res = []
        def backtrack(path, open_count, close_count):
            if len(path) == 2 * n:
                res.append(''.join(path))
                return
            if open_count < n:
                path.append('(')
                backtrack(path, open_count + 1, close_count)
                path.pop()
            if close_count < open_count:
                path.append(')')
                backtrack(path, open_count, close_count + 1)
                path.pop()
        backtrack([], 0, 0)
        return res

class Solution {
    public List<String> generateParenthesis(int n) {
        List<String> res = new ArrayList<>();
        backtrack(res, new StringBuilder(), 0, 0, n);
        return res;
    }
    private void backtrack(List<String> res, StringBuilder path, int open, int close, int n) {
        if (path.length() == 2 * n) {
            res.add(path.toString());
            return;
        }
        if (open < n) {
            path.append('(');
            backtrack(res, path, open + 1, close, n);
            path.deleteCharAt(path.length() - 1);
        }
        if (close < open) {
            path.append(')');
            backtrack(res, path, open, close + 1, n);
            path.deleteCharAt(path.length() - 1);
        }
    }
}

func exist(board [][]byte, word string) bool {
    m, n := len(board), len(board[0])
    // 定义四个方向的移动
    directions := [][]int{{-1, 0}, {1, 0}, {0, -1}, {0, 1}}

    var dfs func(row, col, index int, visited [][]bool) bool
    dfs = func(row, col, index int, visited [][]bool) bool {
        // 已经找到完整的单词
        if index == len(word) {
            return true
        }

        // 越界检查
        if row < 0 || row >= m || col < 0 || col >= n ||
            visited[row][col] || board[row][col] != word[index] {
            return false
        }

        // 标记当前位置已访问
        visited[row][col] = true

        // 向四个方向探索
        for _, dir := range directions {
            newRow := row + dir[0]
            newCol := col + dir[1]
            if dfs(newRow, newCol, index+1, visited) {
                return true
            }
        }

        // 回溯：恢复当前位置未访问状态
        visited[row][col] = false
        return false
    }

    // 从每个位置开始尝试
    for i := 0; i < m; i++ {
        for j := 0; j < n; j++ {
            // 找到可能的起点
            if board[i][j] == word[0] {
                // 创建访问标记数组
                visited := make([][]bool, m)
                for k := range visited {
                    visited[k] = make([]bool, n)
                }
                // 从这个位置开始搜索
                if dfs(i, j, 0, visited) {
                    return true
                }
            }
        }
    }
    return false
}

class Solution:
    def exist(self, board: List[List[str]], word: str) -> bool:
        rows, cols = len(board), len(board[0])
        def dfs(r, c, i):
            if i == len(word): return True
            if r < 0 or r >= rows or c < 0 or c >= cols or board[r][c] != word[i]: return False
            temp = board[r][c]
            board[r][c] = '#'
            found = dfs(r+1, c, i+1) or dfs(r-1, c, i+1) or dfs(r, c+1, i+1) or dfs(r, c-1, i+1)
            board[r][c] = temp
            return found
        for i in range(rows):
            for j in range(cols):
                if dfs(i, j, 0): return True
        return False

class Solution {
    public boolean exist(char[][] board, String word) {
        for (int i = 0; i < board.length; i++) {
            for (int j = 0; j < board[0].length; j++) {
                if (dfs(board, word, i, j, 0)) return true;
            }
        }
        return false;
    }
    private boolean dfs(char[][] board, String word, int r, int c, int i) {
        if (i == word.length()) return true;
        if (r < 0 || r >= board.length || c < 0 || c >= board[0].length || board[r][c] != word.charAt(i)) return false;
        char temp = board[r][c];
        board[r][c] = '#';
        boolean found = dfs(board, word, r+1, c, i+1) || dfs(board, word, r-1, c, i+1) || dfs(board, word, r, c+1, i+1) || dfs(board, word, r, c-1, i+1);
        board[r][c] = temp;
        return found;
    }
}

func partition(s string) [][]string {
    result := [][]string{}
    current := []string{}
    n := len(s)

    // dp数组用于优化回文串判断
    dp := make([][]bool, n)
    for i := range dp {
        dp[i] = make([]bool, n)
    }

    // 预处理所有可能的回文子串
    for length := 1; length <= n; length++ {
        for i := 0; i <= n-length; i++ {
            j := i + length - 1
            // 长度为1的子串一定是回文
            if length == 1 {
                dp[i][j] = true
            } else if length == 2 {
                // 长度为2的子串，两个字符相等即为回文
                dp[i][j] = s[i] == s[j]
            } else {
                // 长度大于2的子串，首尾字符相等且中间是回文串
                dp[i][j] = s[i] == s[j] && dp[i+1][j-1]
            }
        }
    }

    var backtrack func(start int)
    backtrack = func(start int) {
        // 到达字符串末尾，说明找到一个有效方案
        if start >= n {
            tmp := make([]string, len(current))
            copy(tmp, current)
            result = append(result, tmp)
            return
        }

        // 尝试不同的切割长度
        for end := start; end < n; end++ {
            // 如果当前子串是回文串，继续递归
            if dp[start][end] {
                current = append(current, s[start:end+1])
                backtrack(end + 1)
                current = current[:len(current)-1] // 回溯，撤销选择
            }
        }
    }

    backtrack(0)
    return result
}

class Solution:
    def partition(self, s: str) -> List[List[str]]:
        res = []
        def is_palindrome(sub):
            return sub == sub[::-1]
        def backtrack(start, path):
            if start == len(s):
                res.append(path[:])
                return
            for end in range(start + 1, len(s) + 1):
                if is_palindrome(s[start:end]):
                    path.append(s[start:end])
                    backtrack(end, path)
                    path.pop()
        backtrack(0, [])
        return res

class Solution {
    public List<List<String>> partition(String s) {
        List<List<String>> res = new ArrayList<>();
        backtrack(s, res, new ArrayList<>(), 0);
        return res;
    }
    private void backtrack(String s, List<List<String>> res, List<String> path, int start) {
        if (start == s.length()) {
            res.add(new ArrayList<>(path));
            return;
        }
        for (int end = start + 1; end <= s.length(); end++) {
            if (isPalindrome(s, start, end - 1)) {
                path.add(s.substring(start, end));
                backtrack(s, res, path, end);
                path.remove(path.size() - 1);
            }
        }
    }
    private boolean isPalindrome(String s, int left, int right) {
        while (left < right) {
            if (s.charAt(left++) != s.charAt(right--)) return false;
        }
        return true;
    }
}

func solveNQueens(n int) [][]string {
    result := [][]string{}
    // 用一维数组queens记录每行皇后的列位置
    queens := make([]int, n)
    // 三个布尔数组分别记录：列、主对角线、副对角线的占用情况
    cols := make([]bool, n)
    diag1 := make([]bool, 2*n-1) // 主对角线 r+c
    diag2 := make([]bool, 2*n-1) // 副对角线 r-c+n-1

    var backtrack func(row int)
    backtrack = func(row int) {
        // 成功放置完所有皇后
        if row == n {
            result = append(result, generateBoard(queens, n))
            return
        }

        // 尝试在当前行的每一列放置皇后
        for col := 0; col < n; col++ {
            // 计算当前位置的对角线索引
            d1 := row + col
            d2 := row - col + n - 1

            // 如果当前位置不被攻击
            if !cols[col] && !diag1[d1] && !diag2[d2] {
                // 放置皇后
                queens[row] = col
                cols[col] = true
                diag1[d1] = true
                diag2[d2] = true

                // 递归处理下一行
                backtrack(row + 1)

                // 回溯：撤销当前位置的皇后
                cols[col] = false
                diag1[d1] = false
                diag2[d2] = false
            }
        }
    }

    // 从第0行开始放置皇后
    backtrack(0)
    return result
}

func generateBoard(queens []int, n int) []string {
    board := []string{}
    for i := 0; i < n; i++ {
        row := make([]byte, n)
        for j := 0; j < n; j++ {
            row[j] = '.'
        }
        row[queens[i]] = 'Q'
        board = append(board, string(row))
    }
    return board
}

class Solution:
    def solveNQueens(self, n: int) -> List[List[str]]:
        res = []
        board = [['.' for _ in range(n)] for _ in range(n)]
        def is_valid(row, col):
            for i in range(row):
                if board[i][col] == 'Q': return False
            i, j = row - 1, col - 1
            while i >= 0 and j >= 0:
                if board[i][j] == 'Q': return False
                i -= 1
                j -= 1
            i, j = row - 1, col + 1
            while i >= 0 and j < n:
                if board[i][j] == 'Q': return False
                i -= 1
                j += 1
            return True
        def backtrack(row):
            if row == n:
                res.append([''.join(r) for r in board])
                return
            for col in range(n):
                if is_valid(row, col):
                    board[row][col] = 'Q'
                    backtrack(row + 1)
                    board[row][col] = '.'
        backtrack(0)
        return res

class Solution {
    public List<List<String>> solveNQueens(int n) {
        List<List<String>> res = new ArrayList<>();
        char[][] board = new char[n][n];
        for (int i = 0; i < n; i++) Arrays.fill(board[i], '.');
        backtrack(res, board, 0);
        return res;
    }
    private void backtrack(List<List<String>> res, char[][] board, int row) {
        if (row == board.length) {
            List<String> solution = new ArrayList<>();
            for (char[] r : board) solution.add(new String(r));
            res.add(solution);
            return;
        }
        for (int col = 0; col < board.length; col++) {
            if (isValid(board, row, col)) {
                board[row][col] = 'Q';
                backtrack(res, board, row + 1);
                board[row][col] = '.';
            }
        }
    }
    private boolean isValid(char[][] board, int row, int col) {
        for (int i = 0; i < row; i++) if (board[i][col] == 'Q') return false;
        for (int i = row - 1, j = col - 1; i >= 0 && j >= 0; i--, j--) if (board[i][j] == 'Q') return false;
        for (int i = row - 1, j = col + 1; i >= 0 && j < board.length; i--, j++) if (board[i][j] == 'Q') return false;
        return true;
    }
}

thoughtProcess:
让我们看看解决这个问题时，思维是如何逐步进化的：

### 1. 最直观的思路（新手常用）
```go
// 从头到尾遍历一遍
for i := 0; i < len(nums); i++ {
    if nums[i] >= target {
        return i
    }
}
return len(nums)
```
这种方法虽然直观，但时间复杂度是O(n)，没有利用数组已排序的特性。

### 2. 二分查找思路（进阶方案）
既然数组已经排序，我们可以用二分查找将时间复杂度降到O(log n)。

