func searchInsert(nums []int, target int) int {
    left := 0
    right := len(nums) - 1

    // 特殊情况处理：目标值比所有元素都大
    if target > nums[right] {
        return len(nums)
    }

    for left <= right {
        // 计算中间位置，避免整数溢出
        mid := left + (right - left) / 2

        if nums[mid] == target {
            return mid  // 找到目标值
        } else if nums[mid] < target {
            left = mid + 1  // 目标在右半部分
        } else {
            right = mid - 1  // 目标在左半部分
        }
    }

    // 没找到目标值时，left就是插入位置
    return left
}

class Solution:
    def searchInsert(self, nums: List[int], target: int) -> int:
        left, right = 0, len(nums) - 1
        while left <= right:
            mid = (left + right) // 2
            if nums[mid] == target:
                return mid
            elif nums[mid] < target:
                left = mid + 1
            else:
                right = mid - 1
        return left

class Solution {
    public int searchInsert(int[] nums, int target) {
        int left = 0, right = nums.length - 1;
        while (left <= right) {
            int mid = (left + right) / 2;
            if (nums[mid] == target) return mid;
            else if (nums[mid] < target) left = mid + 1;
            else right = mid - 1;
        }
        return left;
    }
}

func searchMatrix(matrix [][]int, target int) bool {
    if len(matrix) == 0 || len(matrix[0]) == 0 {
        return false
    }

    m := len(matrix)
    n := len(matrix[0])

    // 把二维坐标转换成一维来处理
    left := 0
    right := m * n - 1

    for left <= right {
        mid := left + (right - left) / 2
        // 关键转换：从一维索引还原二维坐标
        row := mid / n  // 行号
        col := mid % n  // 列号

        value := matrix[row][col]

        if value == target {
            return true
        } else if value < target {
            left = mid + 1
        } else {
            right = mid - 1
        }
    }

    return false
}

class Solution {
    public boolean searchMatrix(int[][] matrix, int target) {
        int m = matrix.length, n = matrix[0].length;
        int left = 0, right = m * n - 1;
        while (left <= right) {
            int mid = (left + right) / 2;
            int val = matrix[mid / n][mid % n];
            if (val == target) return true;
            else if (val < target) left = mid + 1;
            else right = mid - 1;
        }
        return false;
    }
}

func searchRange(nums []int, target int) []int {
    // 特判：空数组的情况
    if len(nums) == 0 {
        return []int{-1, -1}
    }

    // 分别查找左右边界
    leftBorder := findBorder(nums, target, true)
    rightBorder := findBorder(nums, target, false)

    return []int{leftBorder, rightBorder}
}

// 查找边界的统一函数，isLeft为true时查找左边界，false时查找右边界
func findBorder(nums []int, target int, isLeft bool) int {
    left := 0
    right := len(nums) - 1

    for left <= right {
        mid := left + (right - left) / 2

        if nums[mid] == target {
            // 找到目标值时的处理
            if isLeft {
                // 查找左边界时，收缩右边界
                if mid == 0 || nums[mid - 1] != target {
                    return mid
                }
                right = mid - 1
            } else {
                // 查找右边界时，收缩左边界
                if mid == len(nums) - 1 || nums[mid + 1] != target {
                    return mid
                }
                left = mid + 1
            }
        } else if nums[mid] < target {
            left = mid + 1
        } else {
            right = mid - 1
        }
    }

    return -1  // 没找到目标值
}

class Solution:
    def searchRange(self, nums: List[int], target: int) -> List[int]:
        def findFirst(nums, target):
            left, right = 0, len(nums) - 1
            while left <= right:
                mid = (left + right) // 2
                if nums[mid] >= target:
                    right = mid - 1
                else:
                    left = mid + 1
            return left

        first = findFirst(nums, target)
        last = findFirst(nums, target + 1) - 1

        if first <= last and first < len(nums) and nums[first] == target:
            return [first, last]
        return [-1, -1]

class Solution {
    public int[] searchRange(int[] nums, int target) {
        int first = findFirst(nums, target);
        int last = findFirst(nums, target + 1) - 1;
        if (first <= last && first < nums.length && nums[first] == target) {
            return new int[]{first, last};
        }
        return new int[]{-1, -1};
    }

    private int findFirst(int[] nums, int target) {
        int left = 0, right = nums.length - 1;
        while (left <= right) {
            int mid = (left + right) / 2;
            if (nums[mid] >= target) right = mid - 1;
            else left = mid + 1;
        }
        return left;
    }
}

func search(nums []int, target int) int {
    if len(nums) == 0 {
        return -1
    }

    left := 0
    right := len(nums) - 1

    for left <= right {
        mid := left + (right - left) / 2

        if nums[mid] == target {
            return mid
        }

        // 判断哪一部分是有序的
        if nums[left] <= nums[mid] {  // 左半部分有序
            if target >= nums[left] && target < nums[mid] {
                // target在左半部分
                right = mid - 1
            } else {
                // target在右半部分
                left = mid + 1
            }
        } else {  // 右半部分有序
            if target > nums[mid] && target <= nums[right] {
                // target在右半部分
                left = mid + 1
            } else {
                // target在左半部分
                right = mid - 1
            }
        }
    }

    return -1
}

class Solution:
    def search(self, nums: List[int], target: int) -> int:
        left, right = 0, len(nums) - 1
        while left <= right:
            mid = (left + right) // 2
            if nums[mid] == target:
                return mid
            if nums[left] <= nums[mid]:
                if nums[left] <= target < nums[mid]:
                    right = mid - 1
                else:
                    left = mid + 1
            else:
                if nums[mid] < target <= nums[right]:
                    left = mid + 1
                else:
                    right = mid - 1
        return -1

