func findMin(nums []int) int {
    // 特判：空数组或只有一个元素
    if len(nums) == 0 {
        panic("数组不能为空")
    }
    if len(nums) == 1 {
        return nums[0]
    }

    // 如果数组没有旋转，直接返回第一个元素
    if nums[0] < nums[len(nums) - 1] {
        return nums[0]
    }

    left := 0
    right := len(nums) - 1

    for left <= right {
        // 如果区间只剩一个元素，它就是最小值
        if left == right {
            return nums[left]
        }

        mid := left + (right - left) / 2

        // 如果中间元素大于它的下一个元素，说明找到了"断崖"
        if nums[mid] > nums[mid + 1] {
            return nums[mid + 1]
        }

        // 如果中间元素小于它的前一个元素，说明它就是最小值
        if mid > 0 && nums[mid - 1] > nums[mid] {
            return nums[mid]
        }

        // 判断最小值在哪一侧
        if nums[mid] > nums[0] {
            // 最小值在右侧
            left = mid + 1
        } else {
            // 最小值在左侧
            right = mid - 1
        }
    }

    // 正常情况下不会执行到这里
    return nums[0]
}

class Solution:
