import "math"

func findMedianSortedArrays(nums1 []int, nums2 []int) float64 {
    // 确保 nums1 是较短的数组，优化性能
    if len(nums1) > len(nums2) {
        nums1, nums2 = nums2, nums1
    }

    m := len(nums1)
    n := len(nums2)

    // 在 nums1 的区间 [0, m] 中查找恰当的分割线
    left := 0
    right := m

    for left <= right {
        // nums1 的分割线
        i := (left + right) / 2
        // nums2 的分割线
        j := (m + n + 1) / 2 - i

        // 获取分割线左右的元素
        maxLeft1 := float64(math.MinInt64)
        if i > 0 {
            maxLeft1 = float64(nums1[i - 1])
        }

        minRight1 := float64(math.MaxInt64)
        if i < m {
            minRight1 = float64(nums1[i])
        }

        maxLeft2 := float64(math.MinInt64)
        if j > 0 {
            maxLeft2 = float64(nums2[j - 1])
        }

        minRight2 := float64(math.MaxInt64)
        if j < n {
            minRight2 = float64(nums2[j])
        }

        // 判断是否找到了正确的分割线
        if maxLeft1 <= minRight2 && maxLeft2 <= minRight1 {
            // 找到合适的分割线，计算中位数
            if (m + n) % 2 == 0 {
                return (math.Max(maxLeft1, maxLeft2) + 
                        math.Min(minRight1, minRight2)) / 2.0
            } else {
                return math.Max(maxLeft1, maxLeft2)
            }
        }
        // 调整搜索范围
        if maxLeft1 > minRight2 {
            right = i - 1
        } else {
            left = i + 1
        }
    }

    panic("输入数组不合法")
}

class Solution:
    def findMedianSortedArrays(self, nums1: List[int], nums2: List[int]) -> float:
        if len(nums1) > len(nums2):
            nums1, nums2 = nums2, nums1
        m, n = len(nums1), len(nums2)
        left, right = 0, m
        while left <= right:
            partition1 = (left + right) // 2
            partition2 = (m + n + 1) // 2 - partition1
            maxLeft1 = float('-inf') if partition1 == 0 else nums1[partition1 - 1]
            minRight1 = float('inf') if partition1 == m else nums1[partition1]
            maxLeft2 = float('-inf') if partition2 == 0 else nums2[partition2 - 1]
            minRight2 = float('inf') if partition2 == n else nums2[partition2]
            if maxLeft1 <= minRight2 and maxLeft2 <= minRight1:
                if (m + n) % 2 == 0:
                    return (max(maxLeft1, maxLeft2) + min(minRight1, minRight2)) / 2
                else:
                    return max(maxLeft1, maxLeft2)
            elif maxLeft1 > minRight2:
                right = partition1 - 1
            else:
                left = partition1 + 1
        return 0.0

class Solution {
    public double findMedianSortedArrays(int[] nums1, int[] nums2) {
        if (nums1.length > nums2.length) {
            int[] temp = nums1; nums1 = nums2; nums2 = temp;
        }
        int m = nums1.length, n = nums2.length;
        int left = 0, right = m;
        while (left <= right) {
            int partition1 = (left + right) / 2;
            int partition2 = (m + n + 1) / 2 - partition1;
            int maxLeft1 = partition1 == 0 ? Integer.MIN_VALUE : nums1[partition1 - 1];
            int minRight1 = partition1 == m ? Integer.MAX_VALUE : nums1[partition1];
            int maxLeft2 = partition2 == 0 ? Integer.MIN_VALUE : nums2[partition2 - 1];
            int minRight2 = partition2 == n ? Integer.MAX_VALUE : nums2[partition2];
            if (maxLeft1 <= minRight2 && maxLeft2 <= minRight1) {
                if ((m + n) % 2 == 0) {
                    return (Math.max(maxLeft1, maxLeft2) + Math.min(minRight1, minRight2)) / 2.0;
                } else {
                    return Math.max(maxLeft1, maxLeft2);
                }
            } else if (maxLeft1 > minRight2) {
                right = partition1 - 1;
            } else {
                left = partition1 + 1;
            }
        }
        return 0.0;
    }
}

func isValid(s string) bool {
    // 如果字符串长度为奇数，直接返回false
    if len(s)%2 != 0 {
        return false
    }

    // 创建一个栈来存储左括号
    stack := []byte{}

    // 遍历字符串中的每个字符
    for i := 0; i < len(s); i++ {
        c := s[i]
        if c == '(' || c == '{' || c == '[' {
            // 遇到左括号，将其压入栈中
            stack = append(stack, c)
        } else {
            // 遇到右括号时，如果栈为空，说明没有匹配的左括号
            if len(stack) == 0 {
                return false
            }

            // 获取栈顶的左括号
            left := stack[len(stack)-1]
            stack = stack[:len(stack)-1]

            // 检查括号是否匹配
            isMatch := (c == ')' && left == '(') ||
                       (c == '}' && left == '{') ||
                       (c == ']' && left == '[')

            if !isMatch {
                return false
            }
        }
    }

    // 最后检查栈是否为空，如果不为空说明有未匹配的左括号
    return len(stack) == 0
}

class Solution:
    def isValid(self, s: str) -> bool:
        stack = []
        mapping = {')': '(', '}': '{', ']': '['}
        for char in s:
            if char in mapping:
                top = stack.pop() if stack else '#'
                if mapping[char] != top:
                    return False
            else:
                stack.append(char)
        return not stack

class Solution {
    public boolean isValid(String s) {
        Stack<Character> stack = new Stack<>();
        Map<Character, Character> map = Map.of(')', '(', '}', '{', ']', '[');
        for (char c : s.toCharArray()) {
            if (map.containsKey(c)) {
                if (stack.isEmpty() || stack.pop() != map.get(c)) return false;
            } else {
                stack.push(c);
            }
        }
        return stack.isEmpty();
    }
}

type MinStack struct {
    // 主栈：存储所有元素
    mainStack []int
    // 辅助栈：同步存储最小值
    minStack []int
}

func NewMinStack() *MinStack {
    return &MinStack{
        mainStack: []int{},
        minStack:  []int{},
    }
}

func (s *MinStack) Push(val int) {
    s.mainStack = append(s.mainStack, val)
    // 如果辅助栈为空，或新元素小于等于当前最小值，则将新元素压入辅助栈
    if len(s.minStack) == 0 || val <= s.minStack[len(s.minStack)-1] {
        s.minStack = append(s.minStack, val)
    }
}

func (s *MinStack) Pop() {
    // 如果弹出的元素是当前最小值，辅助栈也要弹出
    if s.mainStack[len(s.mainStack)-1] == s.minStack[len(s.minStack)-1] {
        s.minStack = s.minStack[:len(s.minStack)-1]
    }
    s.mainStack = s.mainStack[:len(s.mainStack)-1]
}

func (s *MinStack) Top() int {
    return s.mainStack[len(s.mainStack)-1]
}

func (s *MinStack) GetMin() int {
    return s.minStack[len(s.minStack)-1]
}

class MinStack:
    def __init__(self):
        self.stack = []
        self.min_stack = []

    def push(self, val: int) -> None:
        self.stack.append(val)
        self.min_stack.append(min(val, self.min_stack[-1] if self.min_stack else val))

    def pop(self) -> None:
        self.stack.pop()
        self.min_stack.pop()

    def top(self) -> int:
        return self.stack[-1]

    def getMin(self) -> int:
        return self.min_stack[-1]

class MinStack {
    private Stack<Integer> stack;
    private Stack<Integer> minStack;
    public MinStack() {
        stack = new Stack<>();
        minStack = new Stack<>();
    }
    public void push(int val) {
        stack.push(val);
        minStack.push(minStack.isEmpty() ? val : Math.min(val, minStack.peek()));
    }
    public void pop() {
        stack.pop();
        minStack.pop();
    }
    public int top() {
        return stack.peek();
    }
    public int getMin() {
        return minStack.peek();
    }
}

