func decodeString(s string) string {
    result := strings.Builder{}

    for index < len(s) {
        currentChar := s[index]

        if unicode.IsDigit(rune(currentChar)) {
            // 处理数字：获取完整的数字值
            count := 0
            for index < len(s) && unicode.IsDigit(rune(s[index])) {
                count = count*10 + int(s[index]-'0')
                index++
            }

            // 跳过'['
            index++

            // 递归处理括号内的内容
            decodedString := decodeString(s)

            // 重复count次
            for i := 0; i < count; i++ {
                result.WriteString(decodedString)
            }

        } else if unicode.IsLetter(rune(currentChar)) {
            // 处理字母：直接添加到结果中
            result.WriteByte(currentChar)
            index++

        } else if currentChar == ']' {
            // 遇到']'：当前层级的解码完成
            index++
            return result.String()

        }
    }

    return result.String()
}

