func decodeString(s string) string {
    countStack := []int{}
    stringStack := []strings.Builder{}
    currentString := strings.Builder{}
    count := 0

    for i := 0; i < len(s); i++ {
        ch := s[i]
        if unicode.IsDigit(rune(ch)) {
            count = count*10 + int(ch-'0')
        } else if ch == '[' {
            countStack = append(countStack, count)
            stringStack = append(stringStack, currentString)
            currentString = strings.Builder{}
            count = 0
        } else if ch == ']' {
            decodedString := currentString.String()
            currentString = stringStack[len(stringStack)-1]
            stringStack = stringStack[:len(stringStack)-1]
            repeatTimes := countStack[len(countStack)-1]
            countStack = countStack[:len(countStack)-1]
            for i := 0; i < repeatTimes; i++ {
                currentString.WriteString(decodedString)
            }
        } else {
            currentString.WriteByte(ch)
        }
    }

    return currentString.String()
}

func dailyTemperatures(temperatures []int) []int {
    n := len(temperatures)
    answer := make([]int, n)  // 存储每天需要等待的天数

    // 栈里存的是日期（数组下标），而不是温度
    stack := []int{}

    // 从第一天开始，一天天往后看
    for today := 0; today < n; today++ {
        // 每来一个新温度，就跟栈顶的日子比较
        // 如果新温度更高，就告诉之前的日子们等待天数
        for len(stack) > 0 && temperatures[today] > temperatures[stack[len(stack)-1]] {
            previousDay := stack[len(stack)-1]
            stack = stack[:len(stack)-1]
            answer[previousDay] = today - previousDay
        }

        // 把今天放入栈中，等待更暖和的天气
        stack = append(stack, today)
    }

    // 栈里剩下的日子，都遇不到更暖和的天气了
    for len(stack) > 0 {
        answer[stack[len(stack)-1]] = 0
        stack = stack[:len(stack)-1]
    }

    return answer
}

