func largestRectangleArea(heights []int) int {
    n := len(heights)
    left := make([]int, n)   // 存储左边第一个比当前柱子矮的位置
    right := make([]int, n)  // 存储右边第一个比当前柱子矮的位置

    // 初始化单调栈
    stack := []int{}

    // 找左边界
    for i := 0; i < n; i++ {
        // 保持栈内高度递增
        for len(stack) > 0 && heights[stack[len(stack)-1]] >= heights[i] {
            stack = stack[:len(stack)-1]
        }
        // 设置左边界
        if len(stack) == 0 {
            left[i] = -1
        } else {
            left[i] = stack[len(stack)-1]
        }
        stack = append(stack, i)
    }

    // 清空栈，准备找右边界
    stack = []int{}

    // 找右边界
    for i := n - 1; i >= 0; i-- {
        for len(stack) > 0 && heights[stack[len(stack)-1]] >= heights[i] {
            stack = stack[:len(stack)-1]
        }
        // 设置右边界
        if len(stack) == 0 {
            right[i] = n
        } else {
            right[i] = stack[len(stack)-1]
        }
        stack = append(stack, i)
    }

    // 计算最大面积
    maxArea := 0
    for i := 0; i < n; i++ {
        // 面积 = 高度 × 宽度
        // 宽度 = 右边界 - 左边界 - 1
        area := heights[i] * (right[i] - left[i] - 1)
        if area > maxArea {
            maxArea = area
        }
    }

    return maxArea
}

func largestRectangleArea(heights []int) int {
    n := len(heights)
    stack := []int{}
    maxArea := 0

    // 遍历所有位置，包括最后一个虚拟位置
    for i := 0; i <= n; i++ {
        var h int
        if i == n {
            h = 0
        } else {
            h = heights[i]
        }

        // 当遇到一个较矮的柱子时，
        // 栈中较高的柱子就可以确定右边界了
        for len(stack) > 0 && heights[stack[len(stack)-1]] > h {
            height := heights[stack[len(stack)-1]]
            stack = stack[:len(stack)-1]
            var width int
            if len(stack) == 0 {
                width = i
            } else {
                width = i - stack[len(stack)-1] - 1
            }
            area := height * width
            if area > maxArea {
                maxArea = area
            }
        }
        stack = append(stack, i)
    }

    return maxArea
}

// 小顶堆类型
type MinHeap []int

func (h MinHeap) Len() int           { return len(h) }
func (h MinHeap) Less(i, j int) bool { return h[i] < h[j] }
func (h MinHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }

func (h *MinHeap) Push(x interface{}) {
    *h = append(*h, x.(int))
}

func (h *MinHeap) Pop() interface{} {
    old := *h
    n := len(old)
    x := old[n-1]
    *h = old[0 : n-1]
    return x
}

func findKthLargest(nums []int, k int) int {
    // 创建小顶堆
    h := &MinHeap{}

    for _, num := range nums {
        heap.Push(h, num)
        // 保持堆的大小为k
        if h.Len() > k {
            heap.Pop(h)
        }
    }

    // 堆顶就是第k大的元素
    return (*h)[0]
}

// 大顶堆类型
type MaxHeap []int

func (h MaxHeap) Len() int           { return len(h) }
func (h MaxHeap) Less(i, j int) bool { return h[i] > h[j] } // 大顶堆：大的在前
func (h MaxHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }

func (h *MaxHeap) Push(x interface{}) {
    *h = append(*h, x.(int))
}

func (h *MaxHeap) Pop() interface{} {
    old := *h
    n := len(old)
    x := old[n-1]
    *h = old[0 : n-1]
    return x
}

func findKthLargest(nums []int, k int) int {
    // 创建大顶堆
    h := &MaxHeap{}

    // 将所有元素加入堆
    for _, num := range nums {
        heap.Push(h, num)
    }

    // 弹出前k-1个元素
    for i := 0; i < k-1; i++ {
        heap.Pop(h)
    }

    // 堆顶就是第k大的元素
    return (*h)[0]
}

func findKthLargest(nums []int, k int) int {
    // 第k大就是第n-k小
    target := len(nums) - k
    left, right := 0, len(nums)-1

    for left < right {
        pivot := partition(nums, left, right)
        if pivot == target {
            break
        } else if pivot < target {
            left = pivot + 1
        } else {
            right = pivot - 1
        }
    }

    return nums[target]
}

func partition(nums []int, left, right int) int {
    pivot := nums[right]
    i := left
    for j := left; j < right; j++ {
        if nums[j] < pivot {
            nums[i], nums[j] = nums[j], nums[i]
            i++
        }
    }
    nums[i], nums[right] = nums[right], nums[i]
    return i
}

// 需要维护一个固定大小的小顶堆
