type MedianFinder struct {
    smallerHalf *MaxHeap // 大顶堆，存储较小的一半数字
    largerHalf  *MinHeap // 小顶堆，存储较大的一半数字
}

func Constructor() MedianFinder {
    return MedianFinder{
        smallerHalf: &MaxHeap{},
        largerHalf:  &MinHeap{},
    }
}

func (mf *MedianFinder) AddNum(num int) {
    // 先把新数字放入大顶堆（较小的一半）
    heap.Push(mf.smallerHalf, num)

    // 确保smallerHalf中的最大数不超过largerHalf中的最小数
    if mf.smallerHalf.Len() > 0 && mf.largerHalf.Len() > 0 && 
        (*mf.smallerHalf)[0] > (*mf.largerHalf)[0] {
        val := heap.Pop(mf.smallerHalf).(int)
        heap.Push(mf.largerHalf, val)
    }

    // 保持两个堆的大小平衡
    // 允许smallerHalf比largerHalf最多多一个元素
    if mf.smallerHalf.Len() > mf.largerHalf.Len()+1 {
        val := heap.Pop(mf.smallerHalf).(int)
        heap.Push(mf.largerHalf, val)
    }
    if mf.largerHalf.Len() > mf.smallerHalf.Len() {
        val := heap.Pop(mf.largerHalf).(int)
        heap.Push(mf.smallerHalf, val)
    }
}

func (mf *MedianFinder) FindMedian() float64 {
    if mf.smallerHalf.Len() > mf.largerHalf.Len() {
        // 奇数个元素时，中位数就是smallerHalf的堆顶
        return float64((*mf.smallerHalf)[0])
    } else {
        // 偶数个元素时，中位数是两个堆顶的平均值
        return float64((*mf.smallerHalf)[0]+(*mf.largerHalf)[0]) / 2.0
    }
}

from heapq import *
class MedianFinder:
    def __init__(self):
        self.small = []  # max heap
        self.large = []  # min heap

    def addNum(self, num: int) -> None:
        if len(self.small) == len(self.large):
            heappush(self.large, -heappushpop(self.small, -num))
        else:
            heappush(self.small, -heappushpop(self.large, num))

    def findMedian(self) -> float:
        if len(self.small) == len(self.large):
            return (-self.small[0] + self.large[0]) / 2
        return self.large[0]

class MedianFinder {
    private PriorityQueue<Integer> small;
    private PriorityQueue<Integer> large;
    public MedianFinder() {
        small = new PriorityQueue<>(Collections.reverseOrder());
        large = new PriorityQueue<>();
    }
    public void addNum(int num) {
        if (small.size() == large.size()) {
            small.offer(num);
            large.offer(small.poll());
        } else {
            large.offer(num);
            small.offer(large.poll());
        }
    }
    public double findMedian() {
        if (small.size() == large.size()) {
            return (small.peek() + large.peek()) / 2.0;
        }
        return large.peek();
    }
}

