func jump(nums []int) int {
    // 如果数组长度为1，已经在终点，不需要跳跃
    if len(nums) <= 1 {
        return 0
    }

    // 记录跳跃次数
    jumps := 0
    // 当前这一跳能够到达的最远位置
    currentMaxReach := 0
    // 下一跳能够到达的最远位置
    nextMaxReach := 0

    // 遍历数组，注意这里只需要遍历到倒数第二个位置
    // 因为一旦能够到达最后一个位置，就不需要再跳了
    for i := 0; i < len(nums)-1; i++ {
        // 更新在遍历过程中能够到达的最远位置
        if i+nums[i] > nextMaxReach {
            nextMaxReach = i + nums[i]
        }

        // 如果到达当前跳跃能到达的最远位置
        // 说明需要进行下一跳了
        if i == currentMaxReach {
            // 更新当前能够到达的最远位置
            currentMaxReach = nextMaxReach
            // 跳跃次数加1
            jumps++

            // 如果已经能够到达最后一个位置，就可以结束了
            if currentMaxReach >= len(nums)-1 {
                break
            }
        }
    }

    return jumps
}

