    for right < n-1 {
        // 找出从当前区间内能够到达的最远位置
        farthest := 0
        for i := left; i <= right; i++ {
            if i+nums[i] > farthest {
                farthest = i + nums[i]
            }
        }

        // 更新下一个区间的边界
        left = right + 1
        right = farthest

        // 完成一次跳跃
        jumps++
    }

    return jumps
}

