func partitionLabels(s string) []int {
    // 记录每个字母最后出现的位置
    lastPos := make([]int, 26)
    for i := 0; i < len(s); i++ {
        lastPos[s[i]-'a'] = i
    }

    result := make([]int, 0)
    start, end := 0, 0

    // 遍历字符串，动态更新片段边界
    for i := 0; i < len(s); i++ {
        // 更新当前片段的结束位置
        if lastPos[s[i]-'a'] > end {
            end = lastPos[s[i]-'a']
        }

        // 如果当前位置到达了片段结束位置
        if i == end {
            result = append(result, end-start+1)
            start = i + 1
        }
    }

    return result
}

class Solution:
    def partitionLabels(self, s: str) -> List[int]:
        last = {c: i for i, c in enumerate(s)}
        res = []
        start = end = 0
        for i, c in enumerate(s):
            end = max(end, last[c])
            if i == end:
                res.append(end - start + 1)
                start = i + 1
        return res

class Solution {
    public List<Integer> partitionLabels(String s) {
        int[] last = new int[26];
        for (int i = 0; i < s.length(); i++) {
            last[s.charAt(i) - 'a'] = i;
        }
        List<Integer> res = new ArrayList<>();
        int start = 0, end = 0;
        for (int i = 0; i < s.length(); i++) {
            end = Math.max(end, last[s.charAt(i) - 'a']);
            if (i == end) {
                res.add(end - start + 1);
                start = i + 1;
            }
        }
        return res;
    }
}

// 方法一：朴素递归（会超时）
func climbStairs(n int) int {
    if n <= 2 {
        return n
    }
    return climbStairs(n-1) + climbStairs(n-2)
}

// 方法二：记忆化递归
func climbStairs(n int) int {
    memo := make([]int, n+1)
    return climb(n, memo)
}

func climb(n int, memo []int) int {
    if n <= 2 {
        return n
    }
    if memo[n] != 0 {
        return memo[n]
    }
    memo[n] = climb(n-1, memo) + climb(n-2, memo)
    return memo[n]
}

// 方法三：动态规划（最终优化版本）
func climbStairs(n int) int {
    if n <= 2 {
        return n
    }

    prev2 := 1  // 代表 dp[i-2]
    prev1 := 2  // 代表 dp[i-1]
    current := 0

    for i := 3; i <= n; i++ {
        current = prev1 + prev2
        prev2 = prev1
        prev1 = current
    }

    return current
}

class Solution:
    def climbStairs(self, n: int) -> int:
        if n <= 2: return n
        a, b = 1, 2
        for _ in range(3, n + 1):
            a, b = b, a + b
        return b

class Solution {
    public int climbStairs(int n) {
        if (n <= 2) return n;
        int a = 1, b = 2;
        for (int i = 3; i <= n; i++) {
            int temp = a + b;
            a = b;
            b = temp;
        }
        return b;
    }
}

// 栈解法
func longestValidParentheses(s string) int {
    maxLen := 0
    stack := make([]int, 0)
    // 放入-1作为哨兵，处理边界情况
    stack = append(stack, -1)

    for i := 0; i < len(s); i++ {
        if s[i] == '(' {
            // 左括号：把下标压入栈
            stack = append(stack, i)
        } else {
            // 右括号：弹出栈顶
            stack = stack[:len(stack)-1]
            if len(stack) == 0 {
                // 栈空了，说明右括号多了，记录新的起点
                stack = append(stack, i)
            } else {
                // 计算当前有效括号长度
                if i-stack[len(stack)-1] > maxLen {
                    maxLen = i - stack[len(stack)-1]
                }
            }
        }
    }
    return maxLen
}

// 动态规划解法
func longestValidParenthesesDP(s string) int {
    maxLen := 0
    // dp[i]表示以i结尾的最长有效括号长度
    dp := make([]int, len(s))

    for i := 1; i < len(s); i++ {
        if s[i] == ')' {
            if s[i-1] == '(' {
                // 情况1：()
                if i >= 2 {
                    dp[i] = dp[i-2] + 2
                } else {
                    dp[i] = 2
                }
            } else if i-dp[i-1] > 0 && s[i-dp[i-1]-1] == '(' {
                // 情况2：((...))
                add := 0
                if i-dp[i-1] >= 2 {
                    add = dp[i-dp[i-1]-2]
                }
                dp[i] = dp[i-1] + 2 + add
            }
            if dp[i] > maxLen {
                maxLen = dp[i]
            }
        }
    }
    return maxLen
}

class Solution:
    def longestValidParentheses(self, s: str) -> int:
        stack = [-1]
        max_len = 0
        for i, char in enumerate(s):
            if char == '(':
                stack.append(i)
            else:
                stack.pop()
                if not stack:
                    stack.append(i)
                else:
                    max_len = max(max_len, i - stack[-1])
        return max_len

class Solution {
    public int longestValidParentheses(String s) {
        Stack<Integer> stack = new Stack<>();
        stack.push(-1);
        int maxLen = 0;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == '(') {
                stack.push(i);
            } else {
                stack.pop();
                if (stack.isEmpty()) {
                    stack.push(i);
                } else {
                    maxLen = Math.max(maxLen, i - stack.peek());
                }
            }
        }
        return maxLen;
    }
}

func generate(numRows int) [][]int {
    triangle := make([][]int, 0)

    // 处理特殊情况
    if numRows == 0 {
        return triangle
    }

    // 第一行总是 [1]
    triangle = append(triangle, []int{1})

    // 逐行构建三角形
    for rowNum := 1; rowNum < numRows; rowNum++ {
        row := make([]int, 0)
        prevRow := triangle[rowNum-1]

        // 每行的第一个数字总是1
        row = append(row, 1)

        // 填充当前行的中间数字
        for j := 1; j < rowNum; j++ {
            // 当前数字等于上一行的左右肩数字之和
            row = append(row, prevRow[j-1]+prevRow[j])
        }

        // 每行的最后一个数字总是1
        row = append(row, 1)

        // 将当前行添加到三角形中
        triangle = append(triangle, row)
    }

    return triangle
}

class Solution:
    def generate(self, numRows: int) -> List[List[int]]:
        res = []
        for i in range(numRows):
            row = [1] * (i + 1)
            for j in range(1, i):
                row[j] = res[i-1][j-1] + res[i-1][j]
            res.append(row)
        return res

class Solution {
    public List<List<Integer>> generate(int numRows) {
        List<List<Integer>> res = new ArrayList<>();
        for (int i = 0; i < numRows; i++) {
            List<Integer> row = new ArrayList<>();
            for (int j = 0; j <= i; j++) {
                if (j == 0 || j == i) row.add(1);
                else row.add(res.get(i-1).get(j-1) + res.get(i-1).get(j));
            }
            res.add(row);
        }
        return res;
    }
}

// 方法一：基础动态规划解法
func rob(nums []int) int {
    if len(nums) == 0 {
        return 0
    }
    if len(nums) == 1 {
        return nums[0]
    }

    // dp[i] 表示偷到第i间房子时能得到的最大金额
    dp := make([]int, len(nums))

    // 初始状态
    dp[0] = nums[0]
    dp[1] = max(nums[0], nums[1])

    // 状态转移
    for i := 2; i < len(nums); i++ {
        dp[i] = max(dp[i-1],         // 不偷当前房子
                   dp[i-2]+nums[i])  // 偷当前房子
    }

    return dp[len(nums)-1]
}

// 方法二：空间优化版本
func robOptimized(nums []int) int {
    if len(nums) == 0 {
        return 0
    }
    if len(nums) == 1 {
        return nums[0]
    }

    // 只需要两个变量记录前两个状态
    prev2 := nums[0]                      // dp[i-2]
    prev1 := max(nums[0], nums[1])        // dp[i-1]
    current := prev1

    for i := 2; i < len(nums); i++ {
        current = max(prev1, prev2+nums[i])
        prev2 = prev1
        prev1 = current
    }

    return current
}

func max(a, b int) int {
    if a > b {
        return a
    }
    return b
}

class Solution:
    def rob(self, nums: List[int]) -> int:
        if not nums: return 0
        if len(nums) == 1: return nums[0]
        prev2, prev1 = 0, nums[0]
        for i in range(1, len(nums)):
            curr = max(prev1, prev2 + nums[i])
            prev2 = prev1
            prev1 = curr
        return prev1

class Solution {
    public int rob(int[] nums) {
        if (nums.length == 0) return 0;
        if (nums.length == 1) return nums[0];
        int prev2 = 0, prev1 = nums[0];
        for (int i = 1; i < nums.length; i++) {
            int curr = Math.max(prev1, prev2 + nums[i]);
            prev2 = prev1;
            prev1 = curr;
        }
        return prev1;
    }
}

import "math"

func numSquares(n int) int {
    // dp[i] 表示组成i需要的最少完全平方数个数
    dp := make([]int, n+1)

    // 初始化：假设最坏情况下都由1组成
    for i := range dp {
        dp[i] = math.MaxInt32
    }
    dp[0] = 0

    // 计算所有小于等于n的完全平方数
    maxSquareRoot := int(math.Sqrt(float64(n)))
    squares := make([]int, maxSquareRoot+1)
    for i := 1; i <= maxSquareRoot; i++ {
        squares[i] = i * i
    }

    // 动态规划过程
    for i := 1; i <= n; i++ {
        // 尝试每个小于i的完全平方数
        for j := 1; j <= maxSquareRoot && squares[j] <= i; j++ {
            dp[i] = min(dp[i], dp[i-squares[j]]+1)
        }
    }

    return dp[n]
}

// 数学方法：四平方和定理
func numSquaresMath(n int) int {
    // 判断是否为完全平方数
    if isSquare(n) {
        return 1
    }

    // 判断是否可以表示为两个完全平方数之和
    for i := 1; i*i <= n; i++ {
        if isSquare(n - i*i) {
            return 2
        }
    }

    // 判断是否是4的倍数乘以8加7
    for n%4 == 0 {
        n /= 4
    }
    if n%8 == 7 {
        return 4
    }

    // 其他情况下一定是3
    return 3
}

func isSquare(n int) bool {
    sqrt := int(math.Sqrt(float64(n)))
    return sqrt*sqrt == n
}

func min(a, b int) int {
    if a < b {
        return a
    }
    return b
}

class Solution:
    def numSquares(self, n: int) -> int:
        dp = [float('inf')] * (n + 1)
        dp[0] = 0
        for i in range(1, n + 1):
            j = 1
            while j * j <= i:
                dp[i] = min(dp[i], dp[i - j * j] + 1)
                j += 1
        return dp[n]

class Solution {
    public int numSquares(int n) {
        int[] dp = new int[n + 1];
        Arrays.fill(dp, Integer.MAX_VALUE);
        dp[0] = 0;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j * j <= i; j++) {
                dp[i] = Math.min(dp[i], dp[i - j * j] + 1);
            }
        }
        return dp[n];
    }
}

import "math"

// 方法一：朴素递归（会超时）
func coinChange(coins []int, amount int) int {
    if amount == 0 {
        return 0
    }
    if amount < 0 {
        return -1
    }

    min := math.MaxInt32
    for _, coin := range coins {
        subResult := coinChange(coins, amount-coin)
        if subResult >= 0 {
            if subResult+1 < min {
                min = subResult + 1
            }
        }
    }

    if min == math.MaxInt32 {
        return -1
    }
    return min
}

// 方法二：记忆化递归
func coinChange(coins []int, amount int) int {
    memo := make([]int, amount+1)
    for i := range memo {
        memo[i] = -2 // 用-2表示未计算过
    }
    return helper(coins, amount, memo)
}

func helper(coins []int, amount int, memo []int) int {
    if amount == 0 {
        return 0
    }
    if amount < 0 {
        return -1
    }
    if memo[amount] != -2 {
        return memo[amount]
    }

    min := math.MaxInt32
    for _, coin := range coins {
        subResult := helper(coins, amount-coin, memo)
        if subResult >= 0 {
            if subResult+1 < min {
                min = subResult + 1
            }
        }
    }

    if min == math.MaxInt32 {
        memo[amount] = -1
    } else {
        memo[amount] = min
    }
    return memo[amount]
}

// 方法三：动态规划（最终优化版本）
func coinChange(coins []int, amount int) int {
    dp := make([]int, amount+1)
    for i := range dp {
        dp[i] = amount + 1 // 初始化为一个不可能的大数
    }
    dp[0] = 0

    for i := 1; i <= amount; i++ {
        for _, coin := range coins {
            if i >= coin {
                if dp[i-coin]+1 < dp[i] {
                    dp[i] = dp[i-coin] + 1
                }
            }
        }
    }

    if dp[amount] > amount {
        return -1
    }
    return dp[amount]
}

class Solution:
    def coinChange(self, coins: List[int], amount: int) -> int:
        dp = [float('inf')] * (amount + 1)
        dp[0] = 0
        for coin in coins:
            for i in range(coin, amount + 1):
                dp[i] = min(dp[i], dp[i - coin] + 1)
        return dp[amount] if dp[amount] != float('inf') else -1

class Solution {
    public int coinChange(int[] coins, int amount) {
        int[] dp = new int[amount + 1];
        Arrays.fill(dp, amount + 1);
        dp[0] = 0;
        for (int coin : coins) {
            for (int i = coin; i <= amount; i++) {
                dp[i] = Math.min(dp[i], dp[i - coin] + 1);
            }
        }
        return dp[amount] > amount ? -1 : dp[amount];
    }
}

thoughtProcess:
### 第一步：暴力递归（超时是必然的）

最直观的想法是：从字符串的每个位置开始，尝试匹配字典中的单词。如果匹配成功，继续处理剩余部分。

```go
import "strings"

// 方法一：朴素递归（会超时）
func wordBreak(s string, wordDict []string) bool {
    // 递归的基本情况：空字符串总是可以被拆分的
    if len(s) == 0 {
        return true
    }

    // 尝试用字典中的每个单词去匹配字符串的开头
    for _, word := range wordDict {
        // 如果当前单词可以匹配字符串的开头
        if strings.HasPrefix(s, word) {
            // 递归处理剩余的子串
            if wordBreak(s[len(word):], wordDict) {
                return true
            }
        }
    }
    return false
}
```

### 第二步：发现问题的本质

让我们通过一个例子来理解为什么这个方法会超时：
```
s = "aaab"
wordDict = ["a", "aa"]
```

画出递归树，你会发现：
- 第一次选择"a"后，需要处理"aab"
- 第一次选择"aa"后，也需要处理"ab"
- 这些子问题在递归过程中被重复计算了多次

这就是典型的"重叠子问题"！启发我们使用动态规划来优化。

### 第三步：设计动态规划解法

关键在于设计状态定义和转移方程：

1. 状态定义：
   dp[i] 表示字符串s的前i个字符能否被拆分成字典中的单词

2. 转移方程：
   dp[i] = dp[j] && check(s[j..i])
   其中j < i，check函数判断子串s[j..i]是否在字典中

3. 边界情况：
   dp[0] = true，表示空字符串可以被拆分

```go
// 方法二：动态规划（最终优化版本）
func wordBreak(s string, wordDict []string) bool {
    dict := make(map[string]bool)
    for _, word := range wordDict {
        dict[word] = true // 转换成map提高查询效率
    }
    dp := make([]bool, len(s)+1)
    dp[0] = true // 空字符串总是可以被拆分的

    // 外层循环：遍历所有子串长度
    for i := 1; i <= len(s); i++ {
        // 内层循环：遍历所有可能的分割点
        for j := 0; j < i; j++ {
            // 如果之前的部分可以被拆分，且剩余部分在字典中
            if dp[j] && dict[s[j:i]] {
                dp[i] = true
                break // 找到一种可行的拆分方式就可以了
            }
        }
    }

    return dp[len(s)]
}
```

### 第四步：优化细节

为了进一步提升性能，我们可以添加一些剪枝条件：

```go
import (
    "math"
    "strings"
)

// 方法三：优化后的动态规划
func wordBreakOptimized(s string, wordDict []string) bool {
    dict := make(map[string]bool)
    for _, word := range wordDict {
        dict[word] = true
    }
    dp := make([]bool, len(s)+1)
    dp[0] = true

    // 找出字典中最长和最短的单词长度
    maxLen, minLen := 0, math.MaxInt32
    for word := range dict {
        if len(word) > maxLen {
            maxLen = len(word)
        }
        if len(word) < minLen {
            minLen = len(word)
        }
    }

    for i := minLen; i <= len(s); i++ {
        // 只考虑符合长度范围的子串
        start := i - maxLen
        if start < 0 {
            start = 0
        }
        for j := start; j < i; j++ {
            if dp[j] && dict[s[j:i]] {
                dp[i] = true
                break
            }
        }
    }

    return dp[len(s)]
}
