func lengthOfLIS(nums []int) int {
    if len(nums) == 0 {
        return 0
    }

    // dp[i]表示以nums[i]结尾的最长递增子序列的长度
    dp := make([]int, len(nums))
    // 初始化:每个数字本身就是长度为1的子序列
    for i := range dp {
        dp[i] = 1
    }

    // 最终的结果(全局最大值)
    maxLen := 1

    // 遍历每个位置,计算以该位置结尾的LIS长度
    for i := 1; i < len(nums); i++ {
        // 查看i之前的所有数字
        for j := 0; j < i; j++ {
            // 如果当前数字大于之前的数字,可以接在该数字后面形成更长的递增子序列
            if nums[i] > nums[j] {
                if dp[j]+1 > dp[i] {
                    dp[i] = dp[j] + 1
                }
            }
        }
        // 更新全局最大长度
        if dp[i] > maxLen {
            maxLen = dp[i]
        }
    }

    return maxLen
}

