func maxProduct(nums []int) int {
    // 至少会有一个数
    if len(nums) == 0 {
        return 0
    }

    // 初始化：第一个数既是最大值也是最小值
    maxVal := nums[0]
    minVal := nums[0]
    // 记录全局最大值
    result := nums[0]

    // 从第二个数开始遍历
    for i := 1; i < len(nums); i++ {
        // 临时保存上一个最大值，因为计算最小值时会用到
        temp := maxVal

        // 计算当前位置的最大值
        // 可能是：当前数、前面最大值×当前数、前面最小值×当前数
        maxVal = max(nums[i], max(maxVal*nums[i], minVal*nums[i]))

        // 计算当前位置的最小值
        minVal = min(nums[i], min(temp*nums[i], minVal*nums[i]))

        // 更新全局最大值
        result = max(result, maxVal)
    }

    return result
}

