    }

    // 初始化第一行
    for j := 0; j < n; j++ {
        dp[0][j] = 1
    }

    // 初始化第一列
    for i := 0; i < m; i++ {
        dp[i][0] = 1
    }

    // 填充dp数组
    for i := 1; i < m; i++ {
        for j := 1; j < n; j++ {
            dp[i][j] = dp[i-1][j] + dp[i][j-1]
        }
    }

    return dp[m-1][n-1]
}

