func longestPalindrome(s string) string {
    if len(s) < 1 {
        return ""
    }

    start, end := 0, 0
    for i := 0; i < len(s); i++ {
        len1 := expandAroundCenter(s, i, i)     // 奇数长度
        len2 := expandAroundCenter(s, i, i+1)   // 偶数长度
        length := max(len1, len2)

        if length > end-start {
            start = i - (length-1)/2
            end = i + length/2
        }
    }

    return s[start:end+1]
}

func expandAroundCenter(s string, left, right int) int {
    for left >= 0 && right < len(s) && s[left] == s[right] {
        left--
        right++
    }
    return right - left - 1 // 回文的长度
}

func longestPalindrome(s string) string {
    n := len(s)
    dp := make([][]bool, n)
    for i := range dp {
        dp[i] = make([]bool, n)
    }
    result := ""

    // 单个字符都是回文
    for i := 0; i < n; i++ {
        dp[i][i] = true
        result = s[i : i+1]
    }

    // 检查长度为2的子串
    for i := 0; i < n-1; i++ {
        if s[i] == s[i+1] {
            dp[i][i+1] = true
            result = s[i : i+2]
        }
    }

    // 检查长度大于2的子串
    for length := 3; length <= n; length++ {
        for i := 0; i <= n-length; i++ {
            j := i + length - 1
            if s[i] == s[j] && dp[i+1][j-1] {
                dp[i][j] = true
                if length > len(result) {
                    result = s[i : j+1]
                }
            }
        }
    }

    return result
}

func longestPalindrome(s string) string {
    if len(s) < 1 {
        return ""
    }

    // 预处理，插入特殊字符#
    t := "#"
    for _, c := range s {
        t += string(c) + "#"
    }

    n := len(t)
    p := make([]int, n) // p[i]表示以i为中心的回文半径
    center, right := 0, 0
    maxLen, maxCenter := 0, 0

    for i := 0; i < n; i++ {
        // 利用对称性初始化p[i]
        if right > i {
            p[i] = min(p[2*center-i], right-i)
        }

        // 中心扩展
        for i-p[i]-1 >= 0 && i+p[i]+1 < n && t[i-p[i]-1] == t[i+p[i]+1] {
            p[i]++
        }

        // 更新center和right
        if i+p[i] > right {
            center = i
            right = i + p[i]
        }

        // 更新最长回文
        if p[i] > maxLen {
            maxLen = p[i]
            maxCenter = i
        }
    }

    // 从处理后的字符串中提取回文
    start := (maxCenter - maxLen) / 2
    return s[start : start+maxLen]
}

class Solution:
    def longestPalindrome(self, s: str) -> str:
        if not s:
            return ""
        start, end = 0, 0
        for i in range(len(s)):
            len1 = self.expandAroundCenter(s, i, i)
            len2 = self.expandAroundCenter(s, i, i + 1)
            max_len = max(len1, len2)
            if max_len > end - start:
                start = i - (max_len - 1) // 2
                end = i + max_len // 2
        return s[start:end + 1]

    def expandAroundCenter(self, s, left, right):
        while left >= 0 and right < len(s) and s[left] == s[right]:
            left -= 1
            right += 1
        return right - left - 1

class Solution {
    public String longestPalindrome(String s) {
        if (s == null || s.length() == 0) return "";
        int start = 0, end = 0;
        for (int i = 0; i < s.length(); i++) {
            int len1 = expandAroundCenter(s, i, i);
            int len2 = expandAroundCenter(s, i, i + 1);
            int maxLen = Math.max(len1, len2);
            if (maxLen > end - start) {
                start = i - (maxLen - 1) / 2;
                end = i + maxLen / 2;
            }
        }
        return s.substring(start, end + 1);
    }

    private int expandAroundCenter(String s, int left, int right) {
        while (left >= 0 && right < s.length() && s.charAt(left) == s.charAt(right)) {
            left--;
            right++;
        }
        return right - left - 1;
    }
}

func longestCommonSubsequence(text1 string, text2 string) int {
    m := len(text1)
    n := len(text2)
    dp := make([][]int, m+1)
    for i := range dp {
        dp[i] = make([]int, n+1)
    }

    // dp[i][j]表示text1[0...i-1]和text2[0...j-1]的LCS长度
    for i := 1; i <= m; i++ {
        for j := 1; j <= n; j++ {
            if text1[i-1] == text2[j-1] {
                dp[i][j] = dp[i-1][j-1] + 1
            } else {
                dp[i][j] = max(dp[i-1][j], dp[i][j-1])
            }
        }
    }

    return dp[m][n]
}

func longestCommonSubsequence(text1 string, text2 string) int {
    m := len(text1)
    n := len(text2)

    // 确保text1是较短的字符串，优化空间
    if m > n {
        return longestCommonSubsequence(text2, text1)
    }

    dp := make([]int, n+1)

    for i := 1; i <= m; i++ {
        prev := 0 // dp[i-1][j-1]
        for j := 1; j <= n; j++ {
            curr := dp[j] // 保存dp[i-1][j]
            if text1[i-1] == text2[j-1] {
                dp[j] = prev + 1
            } else {
                dp[j] = max(dp[j], dp[j-1])
            }
            prev = curr // 为下一次循环更新dp[i-1][j-1]
        }
    }

    return dp[n]
}

