func minDistance(word1 string, word2 string) int {
    m := len(word1)
    n := len(word2)

    // dp[i][j]表示word1的前i个字符转换到word2的前j个字符的最少操作数
    dp := make([][]int, m+1)
    for i := range dp {
        dp[i] = make([]int, n+1)
    }

    // 初始化：将word1的前i个字符转换为空字符串，需要删除i次
    for i := 0; i <= m; i++ {
        dp[i][0] = i
    }

    // 初始化：将空字符串转换为word2的前j个字符，需要插入j次
    for j := 0; j <= n; j++ {
        dp[0][j] = j
    }

    for i := 1; i <= m; i++ {
        for j := 1; j <= n; j++ {
            if word1[i-1] == word2[j-1] {
                dp[i][j] = dp[i-1][j-1]
            } else {
                dp[i][j] = 1 + min(dp[i-1][j-1],  // 替换
                            min(dp[i][j-1],     // 插入
                                dp[i-1][j]))    // 删除
            }
        }
    }

    return dp[m][n]
}

func minDistance(word1 string, word2 string) int {
    m := len(word1)
    n := len(word2)

    // 确保word1是较短的字符串，优化空间
    if m > n {
        return minDistance(word2, word1)
    }

    // 只保留两行
    prev := make([]int, n+1)
    curr := make([]int, n+1)

    // 初始化第一行
    for j := 0; j <= n; j++ {
        prev[j] = j
    }

    for i := 1; i <= m; i++ {
        curr[0] = i // 初始化每行的第一个元素

        for j := 1; j <= n; j++ {
            if word1[i-1] == word2[j-1] {
                curr[j] = prev[j-1]
            } else {
                curr[j] = 1 + min(prev[j-1],  // 替换
                            min(curr[j-1],   // 插入
                                prev[j]))    // 删除
            }
        }

        // 交换行
        prev, curr = curr, prev
    }

    return prev[n]
}

func minDistance(word1 string, word2 string) int {
    m := len(word1)
    n := len(word2)

    dp := make([]int, n+1)

    // 初始化
    for j := 0; j <= n; j++ {
        dp[j] = j
    }

    for i := 1; i <= m; i++ {
        prev := dp[0] // 保存左上角的值
        dp[0] = i     // 更新dp[0]

        for j := 1; j <= n; j++ {
            temp := dp[j] // 保存当前dp[j]用于下次循环

            if word1[i-1] == word2[j-1] {
                dp[j] = prev
            } else {
                dp[j] = 1 + min(prev,      // 替换
                            min(dp[j-1],   // 插入
                                dp[j]))    // 删除
            }

            prev = temp // 更新左上角的值为原来的dp[j]
        }
    }

    return dp[n]
}

class Solution:
