func singleNumber(nums []int) int {
    countMap := make(map[int]int)

    // 统计每个元素出现的次数
    for _, num := range nums {
        countMap[num]++
    }

    // 找出只出现一次的元素
    for key, val := range countMap {
        if val == 1 {
            return key
        }
    }

    return -1 // 如果没有只出现一次的元素，返回-1
}

func singleNumber(nums []int) int {
