}

func singleNumber(nums []int) int {
    result := 0

    // 考虑每一个二进制位
    for i := 0; i < 32; i++ {
        sum := 0
        bit := 1 << i

        // 统计所有数字在当前位上的1的个数
        for _, num := range nums {
            if (num & bit) != 0 {
                sum++
            }
        }

        // 如果sum不是3的倍数，说明只出现一次的数在这一位上为1
        if sum%3 != 0 {
            result |= bit
        }
    }

    return result
}

