func majorityElement(nums []int) int {
    // 创建哈希表记录每个元素出现的次数
    counts := make(map[int]int)

    // 计数阶段
    for _, num := range nums {
        counts[num]++
    }

    // 寻找多数元素
    majority := 0
    maxCount := 0

    for num, count := range counts {
        if count > maxCount {
            maxCount = count
            majority = num
        }
    }

    return majority
}

