    count := 0
    var candidate int

    for _, num := range nums {
        if count == 0 {
            candidate = num
        }
        if num == candidate {
            count++
        } else {
            count--
        }
    }

    // 验证候选人是否真的是多数元素
    count = 0
    for _, num := range nums {
