class Solution {
    public int majorityElement(int[] nums) {
        int count = 0, candidate = 0;
        for (int num : nums) {
            if (count == 0) candidate = num;
            count += (num == candidate) ? 1 : -1;
        }
        return candidate;
    }
}

func sortColors(nums []int) {
    // 计数
    count0, count1, count2 := 0, 0, 0
    for _, num := range nums {
        if num == 0 {
            count0++
        } else if num == 1 {
            count1++
        } else if num == 2 {
            count2++
        }
    }

    // 重新填充数组
    i := 0
    for count0 > 0 {
        nums[i] = 0
        i++
        count0--
    }
    for count1 > 0 {
        nums[i] = 1
        i++
        count1--
    }
    for count2 > 0 {
        nums[i] = 2
        i++
        count2--
    }
}

func sortColors(nums []int) {
    p0 := 0    // 下一个0应该放置的位置
    p1 := 0    // 下一个1应该放置的位置

    for i := 0; i < len(nums); i++ {
        if nums[i] == 0 {
            // 交换当前元素与p0位置的元素
            nums[i], nums[p0] = nums[p0], nums[i]

            // 如果p0小于p1，说明我们把一个1换到了当前位置
            // 需要再次交换，将1放到正确的位置
            if p0 < p1 {
                nums[i], nums[p1] = nums[p1], nums[i]
            }

            p0++
            p1++
        } else if nums[i] == 1 {
            // 交换当前元素与p1位置的元素
            nums[i], nums[p1] = nums[p1], nums[i]

            p1++
        }
    }
}

func sortColors(nums []int) {
    p0 := 0              // 指向下一个应放0的位置
    p2 := len(nums) - 1  // 指向下一个应放2的位置
    curr := 0            // 当前处理的元素

    for curr <= p2 {
        if nums[curr] == 0 {
            // 遇到0，与p0位置交换，并移动p0和curr
            nums[curr], nums[p0] = nums[p0], nums[curr]
            p0++
            curr++
        } else if nums[curr] == 2 {
            // 遇到2，与p2位置交换，并移动p2
            // 注意此时curr不移动，因为交换来的元素还未处理
            nums[curr], nums[p2] = nums[p2], nums[curr]
            p2--
        } else {
            // 遇到1，只移动curr
            curr++
        }
    }
}

func sortColorsK(nums []int, k int) {
    // 计数排序思路
    counts := make([]int, k)

    // 统计每种颜色的数量
    for _, num := range nums {
        counts[num]++
    }

    // 重新填充数组
    index := 0
    for color := 0; color < k; color++ {
        for count := 0; count < counts[color]; count++ {
            nums[index] = color
            index++
        }
    }
}

