func nextPermutation(nums []int) {
    n := len(nums)
    i := n - 2

    // 步骤1：找到第一个满足 nums[i] < nums[i+1] 的元素
    for i >= 0 && nums[i] >= nums[i+1] {
        i--
    }

    // 如果找到了这样的元素
    if i >= 0 {
        j := n - 1
        // 步骤2：找到第一个满足 nums[j] > nums[i] 的元素
        for j >= 0 && nums[j] <= nums[i] {
            j--
        }
        // 步骤3：交换 nums[i] 和 nums[j]
        nums[i], nums[j] = nums[j], nums[i]
    }

    // 步骤4：将 i+1 到末尾的元素逆序
    reverse(nums, i+1, n-1)
}

func reverse(nums []int, start, end int) {
    for start < end {
        nums[start], nums[end] = nums[end], nums[start]
        start++
        end--
    }
}

import (
    "sort"
)

func permute(nums []int) [][]int {
    // 确保数组是有序的
    sort.Ints(nums)

    result := [][]int{}
    hasNext := true

    for hasNext {
        // 添加当前排列
        current := make([]int, len(nums))
        copy(current, nums)
        result = append(result, current)

        // 生成下一个排列
        hasNext = nextPermutationBool(nums)
    }

    return result
}

func nextPermutationBool(nums []int) bool {
    n := len(nums)
    i := n - 2

    for i >= 0 && nums[i] >= nums[i+1] {
        i--
    }

    if i < 0 {
        return false // 没有下一个排列了
    }

    j := n - 1
    for nums[j] <= nums[i] {
        j--
    }

    nums[i], nums[j] = nums[j], nums[i]
    reverse(nums, i+1, n-1)

    return true
}

func reverse(nums []int, start, end int) {
    for start < end {
        nums[start], nums[end] = nums[end], nums[start]
        start++
        end--
    }
}

class Solution:
    def nextPermutation(self, nums: List[int]) -> None:
        i = len(nums) - 2
        while i >= 0 and nums[i] >= nums[i + 1]:
            i -= 1
        if i >= 0:
            j = len(nums) - 1
            while nums[j] <= nums[i]:
                j -= 1
            nums[i], nums[j] = nums[j], nums[i]
        left, right = i + 1, len(nums) - 1
        while left < right:
            nums[left], nums[right] = nums[right], nums[left]
            left += 1
            right -= 1

class Solution {
    public void nextPermutation(int[] nums) {
        int i = nums.length - 2;
        while (i >= 0 && nums[i] >= nums[i + 1]) i--;
        if (i >= 0) {
            int j = nums.length - 1;
            while (nums[j] <= nums[i]) j--;
            int temp = nums[i];
            nums[i] = nums[j];
            nums[j] = temp;
        }
        int left = i + 1, right = nums.length - 1;
        while (left < right) {
            int temp = nums[left];
            nums[left++] = nums[right];
            nums[right--] = temp;
        }
    }
}

func findDuplicate(nums []int) int {
    left := 1                     // 最小可能值
    right := len(nums) - 1        // 最大可能值

    for left < right {
        mid := left + (right-left)/2

        // 计算小于等于mid的元素个数
        count := 0
        for _, num := range nums {
            if num <= mid {
                count++
            }
        }

        // 如果计数大于mid，说明重复元素在左半部分
        if count > mid {
            right = mid
        } else {
            // 否则在右半部分
            left = mid + 1
        }
    }

    return left // 此时left==right就是重复元素
}

func findDuplicate(nums []int) int {
    // 阶段1：找到环中的相遇点
    slow := nums[0]
    fast := nums[0]

    for {
        slow = nums[slow]      // 慢指针走一步
        fast = nums[nums[fast]] // 快指针走两步
        if slow == fast {
            break
        }
    }

    // 阶段2：找到环的入口
    slow = nums[0] // 重置慢指针到起点
    for slow != fast {
        slow = nums[slow] // 慢指针走一步
        fast = nums[fast] // 此时快指针也走一步
    }

    return slow // 环的入口就是重复数
}

class Solution:
    def findDuplicate(self, nums: List[int]) -> int:
        slow = fast = 0
        while True:
            slow = nums[slow]
            fast = nums[nums[fast]]
            if slow == fast:
                break
        slow = 0
        while slow != fast:
            slow = nums[slow]
            fast = nums[fast]
        return slow

class Solution {
    public int findDuplicate(int[] nums) {
        int slow = 0, fast = 0;
        while (true) {
            slow = nums[slow];
            fast = nums[nums[fast]];
            if (slow == fast) break;
        }
        slow = 0;
        while (slow != fast) {
            slow = nums[slow];
            fast = nums[fast];
        }
        return slow;
    }
}

func twoSum(nums []int, target int) []int {
    // 外层循环：拿起第一个数
    for i := 0; i < len(nums); i++ {
        // 内层循环：依次与后面的数配对
        for j := i + 1; j < len(nums); j++ {
            // 如果两数之和等于目标值，返回它们的位置
            if nums[i]+nums[j] == target {
                return []int{i, j}
            }
        }
    }
    // 如果找不到答案，返回空切片
    return []int{}
}

class Solution:
    def twoSum(self, nums: List[int], target: int) -> List[int]:
        seen = {}
        for i, num in enumerate(nums):
            if target - num in seen:
                return [seen[target - num], i]
            seen[num] = i
        return []

class Solution {
    public int[] twoSum(int[] nums, int target) {
        Map<Integer, Integer> seen = new HashMap<>();
        for (int i = 0; i < nums.length; i++) {
            if (seen.containsKey(target - nums[i])) {
                return new int[]{seen.get(target - nums[i]), i};
            }
            seen.put(nums[i], i);
        }
        return new int[]{};
    }
}

func twoSum(nums []int, target int) []int {
    // 创建哈希表，用于存储数字和下标
    numToIndex := make(map[int]int)

    // 遍历数组
    for i, num := range nums {
        // 计算需要的配对数字
        complement := target - num

        // 查找配对数字是否存在
        if idx, ok := numToIndex[complement]; ok {
            // 找到答案，返回两个数字的下标
            return []int{idx, i}
        }

        // 将当前数字和下标放入哈希表
        numToIndex[num] = i
    }

    // 如果找不到答案，返回空切片
    return []int{}
}

