func threeSum(nums []int) [][]int {
    result := make([][]int, 0)
    // 先排序，这对去重和使用双指针非常关键
    sort.Ints(nums)

    for i := 0; i < len(nums)-2; i++ {
        // 如果第一个数就大于0，后面肯定没有解
        if nums[i] > 0 {
            break
        }

        // 跳过重复的第一个数
        if i > 0 && nums[i] == nums[i-1] {
            continue
        }

        // 使用双指针寻找另外两个数
        left := i + 1
        right := len(nums) - 1

        for left < right {
            sum := nums[i] + nums[left] + nums[right]

            if sum == 0 {
                result = append(result, []int{nums[i], nums[left], nums[right]})

                // 跳过重复的数
                for left < right && nums[left] == nums[left+1] {
                    left++
                }
                for left < right && nums[right] == nums[right-1] {
                    right--
                }

                // 继续寻找其他解
                left++
                right--
            } else if sum < 0 {
                left++
            } else {
                right--
            }
        }
    }

    return result
}

