func trap(height []int) int {
    totalWater := 0

    // 遍历每个位置（除去两端）
    for i := 1; i < len(height)-1; i++ {
        leftMax := 0
        rightMax := 0

        // 找出左边最高的柱子
        for j := 0; j <= i; j++ {
            leftMax = max(leftMax, height[j])
        }

        // 找出右边最高的柱子
        for j := i; j < len(height); j++ {
            rightMax = max(rightMax, height[j])
        }

        // 计算当前位置能积的水
        totalWater += min(leftMax, rightMax) - height[i]
    }

    return totalWater
}

