    sortedP := []byte(p)
    sort.Slice(sortedP, func(i, j int) bool { return sortedP[i] < sortedP[j] })

    // 检查每个可能的子串
    for i := 0; i <= len(s)-len(p); i++ {
        // 取出子串并排序
        window := []byte(s[i : i+len(p)])
        sort.Slice(window, func(i, j int) bool { return window[i] < window[j] })

        // 比较排序后的字符串
        if string(window) == string(sortedP) {
            result = append(result, i)
        }
    }

    return result
}

class Solution:
    def findAnagrams(self, s: str, p: str) -> List[int]:
        if len(s) < len(p): return []
        from collections import Counter
        p_count = Counter(p)
        s_count = Counter(s[:len(p)])
        res = []
        if p_count == s_count: res.append(0)
        for i in range(len(p), len(s)):
            s_count[s[i]] = s_count.get(s[i], 0) + 1
            s_count[s[i - len(p)]] -= 1
            if s_count[s[i - len(p)]] == 0:
                del s_count[s[i - len(p)]]
            if p_count == s_count:
                res.append(i - len(p) + 1)
        return res

class Solution {
    public List<Integer> findAnagrams(String s, String p) {
        List<Integer> res = new ArrayList<>();
        if (s.length() < p.length()) return res;
        int[] pCount = new int[26];
        int[] sCount = new int[26];
        for (char c : p.toCharArray()) pCount[c - 'a']++;
        for (int i = 0; i < p.length(); i++) sCount[s.charAt(i) - 'a']++;
        if (Arrays.equals(pCount, sCount)) res.add(0);
        for (int i = p.length(); i < s.length(); i++) {
            sCount[s.charAt(i) - 'a']++;
            sCount[s.charAt(i - p.length()) - 'a']--;
            if (Arrays.equals(pCount, sCount)) res.add(i - p.length() + 1);
        }
        return res;
    }
}

func findAnagrams(s string, p string) []int {
    result := []int{}
    if len(s) < len(p) {
        return result
    }

    // 使用数组记录字符出现次数
    pCount := [26]int{}
    windowCount := [26]int{}

    // 统计p中字符出现次数
    for i := 0; i < len(p); i++ {
        pCount[p[i]-'a']++
    }

    // 初始化窗口
    for i := 0; i < len(p); i++ {
        windowCount[s[i]-'a']++
    }

    // 如果初始窗口就是异位词
    if pCount == windowCount {
        result = append(result, 0)
    }

    // 滑动窗口
    for i := len(p); i < len(s); i++ {
        // 移除窗口最左边的字符
        windowCount[s[i-len(p)]-'a']--
        // 添加新的字符
        windowCount[s[i]-'a']++

        // 比较是否是异位词
        if pCount == windowCount {
            result = append(result, i-len(p)+1)
        }
    }

    return result
}

