        if _, ok := need[c]; ok {
            window[c]++
            // 如果这个字符的数量正好匹配需求，valid加1
            if window[c] == need[c] {
                valid++
            }
        }

        // 当所有字符都匹配后，尝试缩小窗口
        for valid == len(need) {
            // 更新最小覆盖子串
            if right-left < minLen {
                start = left
                minLen = right - left
            }

            // 缩小窗口
            d := s[left]
            left++

            // 如果移出的是需要的字符，更新窗口数据
            if _, ok := need[d]; ok {
                if window[d] == need[d] {
                    valid--
                }
                window[d]--
            }
        }
    }

    if minLen == int(^uint(0)>>1) {
        return ""
    }
    return s[start : start+minLen]
}

class Solution:
    def minWindow(self, s: str, t: str) -> str:
        if not s or not t or len(s) < len(t): return ""
        from collections import Counter
        t_count = Counter(t)
        required = len(t_count)
        formed = 0
        window = {}
        l = 0
        min_len = float('inf')
        min_l = 0
        for r, c in enumerate(s):
            window[c] = window.get(c, 0) + 1
            if c in t_count and window[c] == t_count[c]:
                formed += 1
            while formed == required:
                if r - l + 1 < min_len:
                    min_len = r - l + 1
                    min_l = l
                window[s[l]] -= 1
                if s[l] in t_count and window[s[l]] < t_count[s[l]]:
                    formed -= 1
                l += 1
        return s[min_l:min_l + min_len] if min_len != float('inf') else ""

class Solution {
    public String minWindow(String s, String t) {
        if (s == null || t == null || s.length() < t.length()) return "";
        Map<Character, Integer> tCount = new HashMap<>();
        for (char c : t.toCharArray()) tCount.put(c, tCount.getOrDefault(c, 0) + 1);
        int required = tCount.size(), formed = 0;
        Map<Character, Integer> window = new HashMap<>();
        int l = 0, minLen = Integer.MAX_VALUE, minL = 0;
        for (int r = 0; r < s.length(); r++) {
            char c = s.charAt(r);
            window.put(c, window.getOrDefault(c, 0) + 1);
            if (tCount.containsKey(c) && window.get(c).intValue() == tCount.get(c).intValue()) formed++;
            while (formed == required) {
                if (r - l + 1 < minLen) {
                    minLen = r - l + 1;
                    minL = l;
                }
                char leftChar = s.charAt(l);
                window.put(leftChar, window.get(leftChar) - 1);
                if (tCount.containsKey(leftChar) && window.get(leftChar) < tCount.get(leftChar)) formed--;
                l++;
            }
        }
        return minLen == Integer.MAX_VALUE ? "" : s.substring(minL, minL + minLen);
    }
}

func maxSubArray(nums []int) int {
    if len(nums) == 0 {
        return 0
    }

    // dp[i]表示以i结尾的最大子数组和
    dp := make([]int, len(nums))
    dp[0] = nums[0]
    maxSum := dp[0]

    for i := 1; i < len(nums); i++ {
        // 状态转移：要么接续前面的和，要么重新开始
        dp[i] = max(dp[i-1]+nums[i], nums[i])
        // 更新全局最大和
        maxSum = max(maxSum, dp[i])
    }

    return maxSum
}

class Solution:
    def maxSubArray(self, nums: List[int]) -> int:
        max_sum = nums[0]
        current_sum = nums[0]
        for num in nums[1:]:
            current_sum = max(num, current_sum + num)
            max_sum = max(max_sum, current_sum)
        return max_sum

class Solution {
    public int maxSubArray(int[] nums) {
        int maxSum = nums[0], currentSum = nums[0];
        for (int i = 1; i < nums.length; i++) {
            currentSum = Math.max(nums[i], currentSum + nums[i]);
            maxSum = Math.max(maxSum, currentSum);
        }
        return maxSum;
    }
}

func merge(intervals [][]int) [][]int {
    if len(intervals) <= 1 {
        return intervals
    }

    // 按开始时间排序
    sort.Slice(intervals, func(i, j int) bool {
        return intervals[i][0] < intervals[j][0]
    })

    result := make([][]int, 0)
    current := intervals[0]  // 当前正在处理的区间

    for i := 1; i < len(intervals); i++ {
        // 如果当前区间的结束时间 >= 下一个区间的开始时间，合并
        if current[1] >= intervals[i][0] {
            // 更新结束时间为两者中的较大值
            current[1] = max(current[1], intervals[i][1])
        } else {
            // 无法合并，保存当前区间，开始新区间
            result = append(result, current)
            current = intervals[i]
        }
    }

    // 别忘了最后一个区间
    result = append(result, current)

    return result
}

class Solution:
    def merge(self, intervals: List[List[int]]) -> List[List[int]]:
        intervals.sort()
        res = [intervals[0]]
        for interval in intervals[1:]:
            if interval[0] <= res[-1][1]:
                res[-1][1] = max(res[-1][1], interval[1])
            else:
                res.append(interval)
        return res

class Solution {
    public int[][] merge(int[][] intervals) {
        Arrays.sort(intervals, (a, b) -> a[0] - b[0]);
        List<int[]> res = new ArrayList<>();
        res.add(intervals[0]);
        for (int i = 1; i < intervals.length; i++) {
            if (intervals[i][0] <= res.get(res.size() - 1)[1]) {
                res.get(res.size() - 1)[1] = Math.max(res.get(res.size() - 1)[1], intervals[i][1]);
            } else {
                res.add(intervals[i]);
            }
        }
        return res.toArray(new int[res.size()][]);
    }
}

func rotate(nums []int, k int) {
    if len(nums) <= 1 {
        return
    }

    // 处理k大于数组长度的情况
    k = k % len(nums)
    if k == 0 {
        return
    }

    // 1. 翻转整个数组
    reverse(nums, 0, len(nums)-1)

    // 2. 翻转前k个元素
    reverse(nums, 0, k-1)

    // 3. 翻转剩余元素
    reverse(nums, k, len(nums)-1)
}

func reverse(nums []int, start, end int) {
    for start < end {
        // 交换首尾元素
        nums[start], nums[end] = nums[end], nums[start]
        start++
        end--
    }
}

