func productExceptSelf(nums []int) []int {
    n := len(nums)
    result := make([]int, n)

    // 计算左边的乘积
    result[0] = 1  // 第一个数左边没有其他数
    for i := 1; i < n; i++ {
        result[i] = result[i-1] * nums[i-1]
    }

    // 从右向左遍历，同时计算右边的乘积
    rightProduct := 1
    for i := n - 1; i >= 0; i-- {
        result[i] *= rightProduct
        rightProduct *= nums[i]
    }

    return result
}

class Solution:
    def productExceptSelf(self, nums: List[int]) -> List[int]:
        n = len(nums)
        res = [1] * n
        left = 1
        for i in range(n):
            res[i] = left
            left *= nums[i]
        right = 1
        for i in range(n - 1, -1, -1):
            res[i] *= right
            right *= nums[i]
        return res

class Solution {
    public int[] productExceptSelf(int[] nums) {
        int n = nums.length;
        int[] res = new int[n];
        Arrays.fill(res, 1);
        int left = 1;
        for (int i = 0; i < n; i++) {
            res[i] = left;
            left *= nums[i];
        }
        int right = 1;
        for (int i = n - 1; i >= 0; i--) {
            res[i] *= right;
            right *= nums[i];
        }
        return res;
    }
}

func firstMissingPositive(nums []int) int {
    n := len(nums)

    // 第一遍遍历：把每个数放到它应该在的位置
    for i := 0; i < n; i++ {
        // 当前数在有效范围内，且不在正确位置上
        for nums[i] > 0 && nums[i] <= n && nums[i] != nums[nums[i]-1] {
            // 交换到正确位置
            nums[nums[i]-1], nums[i] = nums[i], nums[nums[i]-1]
        }
    }

    // 第二遍遍历：找出第一个不在正确位置上的数
    for i := 0; i < n; i++ {
        if nums[i] != i+1 {
            return i + 1
        }
    }

    // 如果都正确，返回n+1
    return n + 1
}

class Solution:
    def firstMissingPositive(self, nums: List[int]) -> int:
        n = len(nums)
        for i in range(n):
            while 1 <= nums[i] <= n and nums[nums[i] - 1] != nums[i]:
                nums[nums[i] - 1], nums[i] = nums[i], nums[nums[i] - 1]
        for i in range(n):
            if nums[i] != i + 1:
                return i + 1
        return n + 1

class Solution {
    public int firstMissingPositive(int[] nums) {
        int n = nums.length;
        for (int i = 0; i < n; i++) {
            while (nums[i] >= 1 && nums[i] <= n && nums[nums[i] - 1] != nums[i]) {
                int temp = nums[nums[i] - 1];
                nums[nums[i] - 1] = nums[i];
                nums[i] = temp;
            }
        }
        for (int i = 0; i < n; i++) {
            if (nums[i] != i + 1) return i + 1;
        }
        return n + 1;
    }
}

func setZeroes(matrix [][]int) {
    if len(matrix) == 0 {
        return
    }

    m := len(matrix)
    n := len(matrix[0])

    // 记录第一行和第一列是否原本包含0
    firstRowHasZero := false
    firstColHasZero := false

    // 检查第一行
    for j := 0; j < n; j++ {
        if matrix[0][j] == 0 {
            firstRowHasZero = true
            break
        }
    }

    // 检查第一列
    for i := 0; i < m; i++ {
        if matrix[i][0] == 0 {
            firstColHasZero = true
            break
        }
    }

    // 使用第一行和第一列作为标记
    for i := 1; i < m; i++ {
        for j := 1; j < n; j++ {
            if matrix[i][j] == 0 {
                matrix[i][0] = 0  // 标记该行
                matrix[0][j] = 0  // 标记该列
            }
        }
    }

    // 根据标记处理非第一行第一列的部分
    for i := 1; i < m; i++ {
        for j := 1; j < n; j++ {
            if matrix[i][0] == 0 || matrix[0][j] == 0 {
                matrix[i][j] = 0
            }
        }
    }

    // 处理第一行
    if firstRowHasZero {
        for j := 0; j < n; j++ {
            matrix[0][j] = 0
        }
    }

    // 处理第一列
    if firstColHasZero {
        for i := 0; i < m; i++ {
            matrix[i][0] = 0
        }
    }
}

class Solution:
    def setZeroes(self, matrix: List[List[int]]) -> None:
        m, n = len(matrix), len(matrix[0])
        first_row_zero = any(matrix[0][j] == 0 for j in range(n))
        first_col_zero = any(matrix[i][0] == 0 for i in range(m))
        for i in range(1, m):
            for j in range(1, n):
                if matrix[i][j] == 0:
                    matrix[i][0] = 0
                    matrix[0][j] = 0
        for i in range(1, m):
            for j in range(1, n):
                if matrix[i][0] == 0 or matrix[0][j] == 0:
                    matrix[i][j] = 0
        if first_row_zero:
            for j in range(n): matrix[0][j] = 0
        if first_col_zero:
            for i in range(m): matrix[i][0] = 0

class Solution {
    public void setZeroes(int[][] matrix) {
        int m = matrix.length, n = matrix[0].length;
        boolean firstRowZero = false, firstColZero = false;
        for (int j = 0; j < n; j++) if (matrix[0][j] == 0) firstRowZero = true;
        for (int i = 0; i < m; i++) if (matrix[i][0] == 0) firstColZero = true;
        for (int i = 1; i < m; i++) {
            for (int j = 1; j < n; j++) {
                if (matrix[i][j] == 0) {
                    matrix[i][0] = 0;
                    matrix[0][j] = 0;
                }
            }
        }
        for (int i = 1; i < m; i++) {
            for (int j = 1; j < n; j++) {
                if (matrix[i][0] == 0 || matrix[0][j] == 0) {
                    matrix[i][j] = 0;
                }
            }
        }
        if (firstRowZero) for (int j = 0; j < n; j++) matrix[0][j] = 0;
        if (firstColZero) for (int i = 0; i < m; i++) matrix[i][0] = 0;
    }
}

func spiralOrder(matrix [][]int) []int {
    result := []int{}
    if len(matrix) == 0 {
        return result
    }

    // 定义四个边界
    top := 0
    bottom := len(matrix) - 1
    left := 0
    right := len(matrix[0]) - 1

    for top <= bottom && left <= right {
        // 向右移动，遍历上边界
        for i := left; i <= right; i++ {
            result = append(result, matrix[top][i])
        }
        top++  // 收缩上边界

        // 向下移动，遍历右边界
        for i := top; i <= bottom; i++ {
            result = append(result, matrix[i][right])
        }
        right--  // 收缩右边界

        if top <= bottom {  // 确保还有行要遍历
            // 向左移动，遍历下边界
            for i := right; i >= left; i-- {
                result = append(result, matrix[bottom][i])
            }
            bottom--  // 收缩下边界
        }

        if left <= right {  // 确保还有列要遍历
            // 向上移动，遍历左边界
            for i := bottom; i >= top; i-- {
                result = append(result, matrix[i][left])
            }
            left++  // 收缩左边界
        }
    }

    return result
}

class Solution:
    def spiralOrder(self, matrix: List[List[int]]) -> List[int]:
        res = []
        if not matrix: return res
        top, bottom = 0, len(matrix) - 1
        left, right = 0, len(matrix[0]) - 1
        while top <= bottom and left <= right:
            for j in range(left, right + 1): res.append(matrix[top][j])
            top += 1
            for i in range(top, bottom + 1): res.append(matrix[i][right])
            right -= 1
            if top <= bottom:
                for j in range(right, left - 1, -1): res.append(matrix[bottom][j])
                bottom -= 1
            if left <= right:
                for i in range(bottom, top - 1, -1): res.append(matrix[i][left])
                left += 1
        return res

class Solution {
    public List<Integer> spiralOrder(int[][] matrix) {
        List<Integer> res = new ArrayList<>();
        if (matrix.length == 0) return res;
        int top = 0, bottom = matrix.length - 1, left = 0, right = matrix[0].length - 1;
        while (top <= bottom && left <= right) {
            for (int j = left; j <= right; j++) res.add(matrix[top][j]);
            top++;
            for (int i = top; i <= bottom; i++) res.add(matrix[i][right]);
            right--;
            if (top <= bottom) {
                for (int j = right; j >= left; j--) res.add(matrix[bottom][j]);
                bottom--;
            }
            if (left <= right) {
                for (int i = bottom; i >= top; i--) res.add(matrix[i][left]);
                left++;
            }
        }
        return res;
    }
}

func rotate(matrix [][]int) {
    n := len(matrix)
    // 创建一个新的n×n数组
    temp := make([][]int, n)
    for i := range temp {
        temp[i] = make([]int, n)
    }

    // 将原矩阵旋转90度后的结果存入临时数组
    for i := 0; i < n; i++ {
        for j := 0; j < n; j++ {
            // 关键转换：第i行第j列的元素，旋转后变成第j行第(n-1-i)列
            temp[j][n-1-i] = matrix[i][j]
        }
    }

    // 将结果复制回原矩阵
    for i := 0; i < n; i++ {
        for j := 0; j < n; j++ {
            matrix[i][j] = temp[i][j]
        }
    }
}

