    visited := make(map[*ListNode]bool)

    // 遍历链表A，将节点加入集合
    current := headA
    for current != nil {
        visited[current] = true
        current = current.Next
    }

    // 遍历链表B，查找第一个在集合中出现的节点
    current = headB
    for current != nil {
        if visited[current] {
            return current
        }
        current = current.Next
    }

    return nil
}

