    // 初始化两个指针
    pointerA := headA
    pointerB := headB

    // 当两个指针不相等时继续移动
    for pointerA != pointerB {
        // 移动指针A，如果到达末尾则转到链表B
        if pointerA == nil {
            pointerA = headB
        } else {
            pointerA = pointerA.Next
        }
        // 移动指针B，如果到达末尾则转到链表A
        if pointerB == nil {
            pointerB = headA
        } else {
            pointerB = pointerB.Next
        }
    }

    // 返回相交点（如果不存在相交点，两个指针都会是nil）
    return pointerA
}

