func reverseKGroup(head *ListNode, k int) *ListNode {
    // 先看看手上有没有k个节点
    curr := head
    count := 0
    for count < k {
        if curr == nil {
            return head // 不够k个，保持原样
        }
        curr = curr.Next
        count++
    }

    // 够k个，开始处理当前这一组
    curr = head
    var prev *ListNode = nil
    for i := 0; i < k; i++ {
        next := curr.Next
        curr.Next = prev
        prev = curr
        curr = next
    }

    // 让"下属"处理后续节点，并把结果接在当前组后面
    head.Next = reverseKGroup(curr, k)

    return prev // 返回当前组的新头节点
}

func reverseKGroup(head *ListNode, k int) *ListNode {
    dummy := &ListNode{Val: 0}
    dummy.Next = head
    prevGroupTail := dummy

    for head != nil {
        // 1. 检查是否还有k个节点
        tail := head
        count := 0
        for count < k && tail != nil {
            tail = tail.Next
            count++
        }
        if count < k {
            break // 不够k个，结束处理
        }

        // 2. 翻转当前k个节点
        curr := head
        prev := tail // 注意：连接到下一组的头部
        for i := 0; i < k; i++ {
            next := curr.Next
            curr.Next = prev
            prev = curr
            curr = next
        }

        // 3. 连接前后
        newGroupHead := prev   // 当前组翻转后的头节点
        oldGroupHead := head   // 记住原来的头节点，它将成为新的尾节点
        prevGroupTail.Next = newGroupHead
        prevGroupTail = oldGroupHead
        head = tail // 移动到下一组的开始
    }

    return dummy.Next
}

class Solution {
    public ListNode reverseKGroup(ListNode head, int k) {
        ListNode dummy = new ListNode(0);
        dummy.next = head;
        ListNode prev = dummy;

        while (true) {
            ListNode node = prev;
            for (int i = 0; i < k; i++) {
                node = node.next;
                if (node == null) return dummy.next;
            }

            ListNode nextPrev = prev.next;
            ListNode[] reversed = reverse(prev.next, k);
            prev.next = reversed[0];
            nextPrev.next = node.next;
            prev = nextPrev;
        }
    }

    private ListNode[] reverse(ListNode head, int k) {
        ListNode prev = null, curr = head;
        for (int i = 0; i < k; i++) {
            ListNode next = curr.next;
            curr.next = prev;
            prev = curr;
            curr = next;
        }
        return new ListNode[]{prev, head};
    }
}

func copyRandomList(head *Node) *Node {
    // 特判：空链表直接返回nil
    if head == nil {
        return nil
    }

    // 创建哈希表存储原节点到新节点的映射
    nodeMap := make(map[*Node]*Node)

    // 第一遍遍历：创建所有新节点
    curr := head
    for curr != nil {
        nodeMap[curr] = &Node{Val: curr.Val}
        curr = curr.Next
    }

    // 第二遍遍历：设置所有新节点的指针
    curr = head
    for curr != nil {
        newNode := nodeMap[curr]
        newNode.Next = nodeMap[curr.Next]     // 可能是nil，map会返回nil
        newNode.Random = nodeMap[curr.Random] // 可能是nil，map会返回nil
        curr = curr.Next
    }

    return nodeMap[head]
}

func copyRandomList(head *Node) *Node {
    if head == nil {
        return nil
    }

    // 第一步：在每个原节点后插入复制节点
    curr := head
    for curr != nil {
        copy := &Node{Val: curr.Val}
        copy.Next = curr.Next
        curr.Next = copy
        curr = copy.Next
    }

    // 第二步：设置复制节点的random指针
    curr = head
    for curr != nil {
        if curr.Random != nil {
            curr.Next.Random = curr.Random.Next
        }
        curr = curr.Next.Next
    }

    // 第三步：分离原始链表和复制链表
    curr = head
    copyHead := head.Next
    currCopy := copyHead
    for curr != nil {
        curr.Next = curr.Next.Next
        if currCopy.Next != nil {
            currCopy.Next = currCopy.Next.Next
        }
        curr = curr.Next
        currCopy = currCopy.Next
    }

    return copyHead
}

class Solution:
    def copyRandomList(self, head: 'Node') -> 'Node':
        if not head: return None
        old_to_new = {}
        curr = head
        while curr:
            old_to_new[curr] = Node(curr.val)
            curr = curr.next
        curr = head
        while curr:
            old_to_new[curr].next = old_to_new.get(curr.next)
            old_to_new[curr].random = old_to_new.get(curr.random)
            curr = curr.next
        return old_to_new[head]

class Solution {
    public Node copyRandomList(Node head) {
        if (head == null) return null;
        Map<Node, Node> map = new HashMap<>();
        Node curr = head;
        while (curr != null) {
            map.put(curr, new Node(curr.val));
            curr = curr.next;
        }
        curr = head;
        while (curr != null) {
            map.get(curr).next = map.get(curr.next);
            map.get(curr).random = map.get(curr.random);
            curr = curr.next;
        }
        return map.get(head);
    }
}

thoughtProcess:
就像整理图书一样，我们可以采用"分而治之"的策略：
1. **分解**：将书架分成大小相近的两半
2. **递归**：分别整理两半的书
3. **合并**：将两组整理好的书按顺序合并

这种方法的优雅之处在于：我们不需要关心子问题是如何被解决的，只需要专注于如何将两个有序的部分合并起来。

### 找中点的艺术
在实现分解步骤时，我们需要一个找中点的巧妙方法 —— 快慢指针。想象两个图书管理员：
- 一个每次移动两个位置（快指针）
- 一个每次移动一个位置（慢指针）
当快指针到达终点时，慢指针正好在中间位置。

### 分治排序的实现
```go
func sortList(head *ListNode) *ListNode {
    // 基本情况：空链表或只有一个节点
    if head == nil || head.Next == nil {
        return head
    }

    // 1. 使用快慢指针找到中点
    slow := head
    fast := head.Next // 注意这里的初始位置
    for fast != nil && fast.Next != nil {
        slow = slow.Next
        fast = fast.Next.Next
    }

    // 2. 断开链表，得到两个子链表
    secondHalf := slow.Next
    slow.Next = nil // 断开连接

    // 3. 递归排序两个子链表
    left := sortList(head)
    right := sortList(secondHalf)

    // 4. 合并两个有序链表
    return mergeTwoLists(left, right)
}

// 合并两个有序链表的辅助函数
func mergeTwoLists(l1, l2 *ListNode) *ListNode {
    dummy := &ListNode{Val: 0}
    curr := dummy

    for l1 != nil && l2 != nil {
        if l1.Val <= l2.Val {
            curr.Next = l1
            l1 = l1.Next
        } else {
            curr.Next = l2
            l2 = l2.Next
        }
        curr = curr.Next
    }

    // 处理剩余节点
    if l1 != nil {
        curr.Next = l1
    } else {
        curr.Next = l2
    }

    return dummy.Next
}
