func sortListIterative(head *ListNode) *ListNode {
    if head == nil || head.Next == nil {
        return head
    }

    // 1. 计算链表长度
    length := 0
    curr := head
    for curr != nil {
        length++
        curr = curr.Next
    }

    // 2. 创建虚拟头节点
    dummy := &ListNode{Val: 0}
    dummy.Next = head

    // 3. 自底向上归并
    // step表示每次归并的子链表长度：1,2,4,8,...
    for step := 1; step < length; step *= 2 {
        prev := dummy
        curr = dummy.Next

        for curr != nil {
            // 3.1 分割第一个子链表
            left := curr
            right := split(left, step)
            curr = split(right, step)

            // 3.2 合并这两个子链表
            prev = merge(left, right, prev)
        }
    }

    return dummy.Next
}

// 分割函数：向前数n个节点，返回下一个节点，并断开连接
func split(head *ListNode, n int) *ListNode {
    for n > 1 && head != nil {
        head = head.Next
        n--
    }

    var rest *ListNode = nil
    if head != nil {
        rest = head.Next
        head.Next = nil
    }
    return rest
}

// 合并函数：合并两个有序链表，返回合并后的尾节点
func merge(l1, l2, prev *ListNode) *ListNode {
    curr := prev

    for l1 != nil && l2 != nil {
        if l1.Val <= l2.Val {
            curr.Next = l1
            l1 = l1.Next
        } else {
            curr.Next = l2
            l2 = l2.Next
        }
        curr = curr.Next
    }

    if l1 != nil {
        curr.Next = l1
    } else {
        curr.Next = l2
    }
    // 找到最后一个节点
    for curr.Next != nil {
        curr = curr.Next
    }

    return curr
}

class Solution {
    public ListNode sortList(ListNode head) {
        if (head == null || head.next == null) return head;
        ListNode slow = head, fast = head.next;
        while (fast != null && fast.next != null) {
            slow = slow.next;
            fast = fast.next.next;
        }
        ListNode mid = slow.next;
        slow.next = null;
        ListNode left = sortList(head);
        ListNode right = sortList(mid);
        ListNode dummy = new ListNode(0), curr = dummy;
        while (left != null && right != null) {
            if (left.val < right.val) {
                curr.next = left;
                left = left.next;
            } else {
                curr.next = right;
                right = right.next;
            }
            curr = curr.next;
        }
        curr.next = left != null ? left : right;
        return dummy.next;
    }
}

import "container/heap"

type MinHeap []*ListNode

func (h MinHeap) Len() int           { return len(h) }
func (h MinHeap) Less(i, j int) bool { return h[i].Val < h[j].Val }
func (h MinHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }
func (h *MinHeap) Push(x interface{}) { *h = append(*h, x.(*ListNode)) }
func (h *MinHeap) Pop() interface{} {
    old := *h
    n := len(old)
    x := old[n-1]
    *h = old[:n-1]
    return x
}

func mergeKLists(lists []*ListNode) *ListNode {
    // 特判：处理空数组或全是空链表的情况
    if len(lists) == 0 {
        return nil
    }

    // 创建优先队列，按节点值升序排列
    h := &MinHeap{}
    heap.Init(h)

    // 将所有链表的头节点加入优先队列
    for _, node := range lists {
        if node != nil {
            heap.Push(h, node)
        }
    }

    // 创建虚拟头节点
    dummy := &ListNode{Val: 0}
    tail := dummy

    // 不断从优先队列中取出最小节点
    for h.Len() > 0 {
        // 取出并移除优先队列中的最小节点
        curr := heap.Pop(h).(*ListNode)
        tail.Next = curr
        tail = tail.Next

        // 如果当前节点还有后续节点，加入优先队列
        if curr.Next != nil {
            heap.Push(h, curr.Next)
        }
    }

    return dummy.Next
}

func mergeKLists(lists []*ListNode) *ListNode {
    if len(lists) == 0 {
        return nil
    }
    return mergeSort(lists, 0, len(lists)-1)
}

func mergeSort(lists []*ListNode, left, right int) *ListNode {
    // 只剩一个链表时直接返回
    if left == right {
        return lists[left]
    }

    // 分治处理
    mid := left + (right-left)/2
    leftList := mergeSort(lists, left, mid)
    rightList := mergeSort(lists, mid+1, right)

    // 合并两个有序链表
    return mergeTwoLists(leftList, rightList)
}

func mergeTwoLists(l1, l2 *ListNode) *ListNode {
    dummy := &ListNode{Val: 0}
    tail := dummy

    for l1 != nil && l2 != nil {
        if l1.Val <= l2.Val {
            tail.Next = l1
            l1 = l1.Next
        } else {
            tail.Next = l2
            l2 = l2.Next
        }
        tail = tail.Next
    }

    if l1 != nil {
        tail.Next = l1
    } else {
        tail.Next = l2
    }
    return dummy.Next
}

