    public ListNode mergeKLists(ListNode[] lists) {
        PriorityQueue<ListNode> heap = new PriorityQueue<>((a, b) -> a.val - b.val);
        for (ListNode node : lists) {
            if (node != null) heap.offer(node);
        }
        ListNode dummy = new ListNode(0), curr = dummy;
        while (!heap.isEmpty()) {
            ListNode node = heap.poll();
            curr.next = node;
            curr = curr.next;
            if (node.next != null) heap.offer(node.next);
        }
        return dummy.next;
    }
}

type DLinkedNode struct {
    Key   int
    Value int
    Prev  *DLinkedNode
    Next  *DLinkedNode
}

func NewDLinkedNode(key, value int) *DLinkedNode {
    return &DLinkedNode{Key: key, Value: value}
}

type LRUCache struct {
    cache    map[int]*DLinkedNode
    head     *DLinkedNode // 虚拟头节点
    tail     *DLinkedNode // 虚拟尾节点
    capacity int
    size     int
}

func Constructor(capacity int) LRUCache {
    l := LRUCache{
        cache:    make(map[int]*DLinkedNode),
        head:     &DLinkedNode{},
        tail:     &DLinkedNode{},
        capacity: capacity,
        size:     0,
    }
    // 初始化双向链表
    l.head.Next = l.tail
    l.tail.Prev = l.head
    return l
}

func (l *LRUCache) Get(key int) int {
    node, ok := l.cache[key]
    if !ok {
        return -1
    }
    // 将访问的节点移到头部
    l.moveToHead(node)
    return node.Value
}

func (l *LRUCache) Put(key int, value int) {
    node, ok := l.cache[key]

    if !ok {
        // 创建新节点
        newNode := NewDLinkedNode(key, value)
        l.cache[key] = newNode
        l.addToHead(newNode)
        l.size++

        // 如果超出容量，删除尾部节点
        if l.size > l.capacity {
            tail := l.removeTail()
            delete(l.cache, tail.Key)
            l.size--
        }
    } else {
        // 更新已存在节点的值
        node.Value = value
        l.moveToHead(node)
    }
}

// 辅助方法：将节点添加到头部
func (l *LRUCache) addToHead(node *DLinkedNode) {
    node.Prev = l.head
    node.Next = l.head.Next
    l.head.Next.Prev = node
    l.head.Next = node
}

// 辅助方法：移除节点
func (l *LRUCache) removeNode(node *DLinkedNode) {
    node.Prev.Next = node.Next
    node.Next.Prev = node.Prev
}

// 辅助方法：将节点移到头部
func (l *LRUCache) moveToHead(node *DLinkedNode) {
    l.removeNode(node)
    l.addToHead(node)
}

// 辅助方法：移除尾部节点
func (l *LRUCache) removeTail() *DLinkedNode {
    res := l.tail.Prev
    l.removeNode(res)
    return res
}

class LRUCache:
    def __init__(self, capacity: int):
        self.cache = {}
        self.capacity = capacity
        from collections import OrderedDict
        self.lru = OrderedDict()

    def get(self, key: int) -> int:
        if key not in self.lru: return -1
        self.lru.move_to_end(key)
        return self.lru[key]

    def put(self, key: int, value: int) -> None:
        if key in self.lru:
            self.lru.move_to_end(key)
        self.lru[key] = value
        if len(self.lru) > self.capacity:
            self.lru.popitem(last=False)

