func reverseList(head *ListNode) *ListNode {
    // 基准情况：空链表或只有一个节点时，直接返回
    if head == nil || head.Next == nil {
        return head
    }

    // 递归反转子链表，获得新的头节点
    // 假设后面的链表已经反转完成，newHead指向反转后的头节点
    newHead := reverseList(head.Next)

    // 关键步骤：把当前节点接到反转后链表的末尾
    // 假设当前是节点2，head.Next是节点3
    // head.Next.Next = head 就是让3指向2
    head.Next.Next = head
    head.Next = nil // 断开2原来的指向，防止形成环

    return newHead
}

func reverseList(head *ListNode) *ListNode {
    var prev *ListNode = nil  // 已翻转部分的头节点
    curr := head              // 当前正在处理的节点

    for curr != nil {
        // 第1步：记住下一个学生，以免等下找不到他
        nextTemp := curr.Next

        // 第2步：让当前学生转身（改变指针指向）
        curr.Next = prev

        // 第3步：教练和助教往后移动一位
        prev = curr     // prev是"助教"，扶着已完成转身的学生
        curr = nextTemp // curr是"教练"，去帮助下一个学生
    }

    return prev  // prev指向最后一个处理的节点，即新的头节点
}

class Solution:
    def reverseList(self, head: ListNode) -> ListNode:
        prev = None
        curr = head
        while curr:
            next_temp = curr.next
            curr.next = prev
            prev = curr
