func detectCycle(head *ListNode) *ListNode {
    // 处理特殊情况
    if head == nil || head.Next == nil {
        return nil
    }

    // 第一阶段：使用快慢指针找到相遇点
    slow := head
    fast := head
    var intersection *ListNode = nil

    for fast != nil && fast.Next != nil {
        slow = slow.Next
        fast = fast.Next.Next
        if slow == fast {
            intersection = slow
            break
        }
    }

    // 如果没有相遇点，说明无环
    if intersection == nil {
        return nil
    }

    // 第二阶段：从头节点和相遇点同时出发，找入环点
    start := head
    for start != intersection {
        start = start.Next
        intersection = intersection.Next
    }

    return start
}

