        while (fast != null) {
            fast = fast.next;
            slow = slow.next;
        }
        slow.next = slow.next.next;
        return dummy.next;
    }
}

func swapPairs(head *ListNode) *ListNode {
    // 基本情况：空链表或只有一个节点
    if head == nil || head.Next == nil {
        return head
    }

    // 获取需要交换的两个节点
    firstNode := head
    secondNode := head.Next

    // 递归处理后续节点
    remainingNodes := swapPairs(secondNode.Next)

    // 执行交换
    secondNode.Next = firstNode
    firstNode.Next = remainingNodes

    return secondNode
}

func swapPairs(head *ListNode) *ListNode {
    // 创建虚拟头节点，简化边界情况处理
    dummy := &ListNode{Val: 0}
    dummy.Next = head
    prev := dummy

    // 当还有一对节点可以交换时
    for prev.Next != nil && prev.Next.Next != nil {
        // 定位待交换的两个节点
        first := prev.Next
        second := prev.Next.Next

        // 执行交换（像舞伴交换位置一样）
        prev.Next = second       // 前面的人牵着第二个节点
        first.Next = second.Next // 第一个节点牵着后面的人
        second.Next = first      // 第二个节点牵着第一个节点

        // 移动到下一对待交换节点
        prev = first
    }

    return dummy.Next
}

class Solution {
    public ListNode swapPairs(ListNode head) {
        ListNode dummy = new ListNode(0);
        dummy.next = head;
        ListNode prev = dummy;
        while (head != null && head.next != null) {
            ListNode first = head, second = head.next;
            prev.next = second;
            first.next = second.next;
            second.next = first;
            prev = first;
            head = first.next;
        }
        return dummy.next;
    }
}

thoughtProcess:
### 第一站：递归的诗意
递归是解决树遍历最自然的方式。就像讲一个故事：要了解整个故事，你需要先了解故事的左半部分，然后是核心情节，最后是右半部分。

```go
func inorderTraversal(root *TreeNode) []int {
    result := []int{}
    traverse(root, &result)
    return result
}

func traverse(node *TreeNode, result *[]int) {
    // 递归的三个基本步骤
    if node == nil {
        return
    }

    // 1. 先访问左子树
    traverse(node.Left, result)

    // 2. 访问当前节点
    *result = append(*result, node.Val)

    // 3. 最后访问右子树
    traverse(node.Right, result)
}
```

### 第二站：迭代的智慧
递归虽然优雅，但对于深度较大的树可能导致栈溢出。迭代提供了一种显式管理"故事进度"的方式。

```go
func inorderTraversal(root *TreeNode) []int {
    result := []int{}
    stack := []*TreeNode{}
    current := root

    for current != nil || len(stack) > 0 {
        // 1. 不断深入左子树
        for current != nil {
            stack = append(stack, current)
            current = current.Left
        }

        // 2. 访问栈顶节点
        current = stack[len(stack)-1]
        stack = stack[:len(stack)-1]
        result = append(result, current.Val)

        // 3. 转向右子树
        current = current.Right
    }

    return result
}
```

