func buildTree(preorder []int, inorder []int) *TreeNode {
    return build(preorder, 0, len(preorder)-1, inorder, 0, len(inorder)-1)
}

func build(pre []int, preStart, preEnd int, in []int, inStart, inEnd int) *TreeNode {
    if preStart > preEnd {
        return nil
    }

    // 定位根节点在中序数组的位置
    rootVal := pre[preStart]
    rootIndex := -1
    for i := inStart; i <= inEnd; i++ {
        if in[i] == rootVal {
            rootIndex = i
            break
        }
    }

    // 计算左子树长度
    leftSize := rootIndex - inStart

    root := &TreeNode{Val: rootVal}
    root.Left = build(pre, preStart+1, preStart+leftSize, in, inStart, rootIndex-1)
    root.Right = build(pre, preStart+leftSize+1, preEnd, in, rootIndex+1, inEnd)
    return root
}

