func buildTree(preorder []int, inorder []int) *TreeNode {
    // 构建哈希映射
    inMap = make(map[int]int)
    for i := 0; i < len(inorder); i++ {
        inMap[inorder[i]] = i
    }
    preIndex = 0
    return build(preorder, 0, len(inorder)-1)
}

func build(pre []int, left, right int) *TreeNode {
    if left > right {
        return nil
    }

    rootVal := pre[preIndex]
    preIndex++
    root := &TreeNode{Val: rootVal}

    // 通过哈希表直接定位
    rootIndex := inMap[rootVal]

    root.Left = build(pre, left, rootIndex-1)
    root.Right = build(pre, rootIndex+1, right)
    return root
}

