    public TreeNode buildTree(int[] preorder, int[] inorder) {
        return build(preorder, 0, preorder.length - 1, inorder, 0, inorder.length - 1);
    }
    private TreeNode build(int[] preorder, int preL, int preR, int[] inorder, int inL, int inR) {
        if (preL > preR) return null;
        TreeNode root = new TreeNode(preorder[preL]);
        int idx = 0;
        for (int i = inL; i <= inR; i++) {
            if (inorder[i] == preorder[preL]) {
                idx = i;
                break;
            }
        }
        int leftSize = idx - inL;
        root.left = build(preorder, preL + 1, preL + leftSize, inorder, inL, idx - 1);
        root.right = build(preorder, preL + leftSize + 1, preR, inorder, idx + 1, inR);
        return root;
    }
}

