func dfs(node *TreeNode, currentSum, targetSum int64, prefixSumMap map[int64]int) int {
    if node == nil {
        return 0
    }

    currentSum += int64(node.Val) // 更新当前路径和
    count := prefixSumMap[currentSum-targetSum] // 查找满足条件的路径

    // 更新哈希表
    prefixSumMap[currentSum]++

    // 递归遍历左右子树
    count += dfs(node.Left, currentSum, targetSum, prefixSumMap)
    count += dfs(node.Right, currentSum, targetSum, prefixSumMap)

    // 回溯，恢复哈希表状态
    prefixSumMap[currentSum]--
    return count
}

