        return 0
    }

    // 使用队列进行层序遍历
    queue := []*TreeNode{root}
    depth := 0

    for len(queue) > 0 {
        size := len(queue)

        // 处理当前层的所有节点
        for i := 0; i < size; i++ {
            node := queue[0]
            queue = queue[1:]

            // 将子节点加入队列
            if node.Left != nil {
                queue = append(queue, node.Left)
            }
            if node.Right != nil {
                queue = append(queue, node.Right)
            }
        }

        // 层数加1
        depth++
    }

    return depth
}

