    queue := []*TreeNode{root}

    for len(queue) > 0 {
        // 取出当前节点
        current := queue[0]
        queue = queue[1:]

        // 交换左右子树
        current.Left, current.Right = current.Right, current.Left

        // 将子节点加入队列继续处理
        if current.Left != nil {
            queue = append(queue, current.Left)
        }
        if current.Right != nil {
            queue = append(queue, current.Right)
        }
    }

    return root
}

