func isMirror(left, right *TreeNode) bool {
    // 两个节点同时为空，对称
    if left == nil && right == nil {
        return true
    }

    // 一个为空，另一个不为空，不对称
    if left == nil || right == nil {
        return false
    }

    // 判断三个条件：
    // 1. 当前节点值相同
    // 2. 左子树的左边 = 右子树的右边
    // 3. 左子树的右边 = 右子树的左边
    return (left.Val == right.Val) &&
        isMirror(left.Left, right.Right) &&
        isMirror(left.Right, right.Left)
}

func isSymmetric(root *TreeNode) bool {
