    // 使用队列模拟镜像遍历
    queue := []*TreeNode{root.Left, root.Right}

    for len(queue) > 0 {
        // 每次取出两个节点进行比较
        left := queue[0]
        right := queue[1]
        queue = queue[2:]

        // 两个节点同时为空，继续
        if left == nil && right == nil {
            continue
        }

        // 一个为空或值不同，不对称
        if left == nil || right == nil || left.Val != right.Val {
            return false
        }

        // 按镜像顺序加入队列：
        // 左节点的左子树 对应 右节点的右子树
        // 左节点的右子树 对应 右节点的左子树
        queue = append(queue, left.Left, right.Right, left.Right, right.Left)
    }

    return true
}

