func check(node *TreeNode, minAllow, maxAllow int64) bool {
    if node == nil {
        return true
    }

    // 当前商品价格是否在允许区间内
    if int64(node.Val) <= minAllow || int64(node.Val) >= maxAllow {
        return false
    }

    // 检查左区（价格必须 < 当前价）
    leftValid := check(node.Left, minAllow, int64(node.Val))

    // 检查右区（价格必须 > 当前价）
    rightValid := check(node.Right, int64(node.Val), maxAllow)

    return leftValid && rightValid
}

func isValidBST(root *TreeNode) bool {
    lastVal := int64(math.MinInt64) // 初始设为极小值

    var traverse func(node *TreeNode) bool
    traverse = func(node *TreeNode) bool {
        if node == nil {
            return true
        }

        // 先检查左边货架
        if !traverse(node.Left) {
            return false
        }

        // 检查当前价格
        if int64(node.Val) <= lastVal {
            return false
        }
        lastVal = int64(node.Val) // 更新记录本

        // 最后检查右边货架
        return traverse(node.Right)
    }

    return traverse(root)
}

def check(node):
    if node == None :
        return True

    if node.Left != None && node.Left.Val >= node.Val :
        return False

    if node.Right != None && node.Right.Val <= node.Val :
        return False

    return check(node.Left) && check(node.Right)

public void check(boolean node) {
    if node == null {
        return true
    }
    if node.Left != null && node.Left.Val >= node.Val {
        return false
    }
    if node.Right != null && node.Right.Val <= node.Val {
        return false
    }
    return check(node.Left) && check(node.Right)
}

func kthSmallest(root *TreeNode, k int) int {
    list := []int{}
    inorder(root, &list)
    return list[k-1]
}

func inorder(node *TreeNode, list *[]int) {
    if node == nil {
        return
    }
    inorder(node.Left, list)
    *list = append(*list, node.Val)
    inorder(node.Right, list)
}

class Solution:
    def kthSmallest(self, root: TreeNode, k: int) -> int:
        self.count = 0
        self.result = None
        def inorder(node):
            if not node or self.result is not None:
                return
            inorder(node.left)
            self.count += 1
            if self.count == k:
                self.result = node.val
                return
            inorder(node.right)
        inorder(root)
        return self.result

class Solution {
    private int count = 0;
    private int result = 0;
    public int kthSmallest(TreeNode root, int k) {
        inorder(root, k);
        return result;
    }
    private void inorder(TreeNode node, int k) {
        if (node == null) return;
        inorder(node.left, k);
        count++;
        if (count == k) {
            result = node.val;
            return;
        }
        inorder(node.right, k);
    }
}

func kthSmallest(root *TreeNode, k int) int {
    stack := []*TreeNode{}
    cur := root
    count := 0

    for cur != nil || len(stack) > 0 {
        // 深入最左端
        for cur != nil {
            stack = append(stack, cur)
            cur = cur.Left
        }

        cur = stack[len(stack)-1]
        stack = stack[:len(stack)-1]
        count++
        if count == k {
            return cur.Val
        }

        // 转向右子树
        cur = cur.Right
    }
    return -1 // 不会执行到这里
}

