func numIslands(grid [][]byte) int {
    if len(grid) == 0 {
        return 0
    }

    islandCount := 0
    rows := len(grid)
    cols := len(grid[0])

    // 探索整个地图
    for i := 0; i < rows; i++ {
        for j := 0; j < cols; j++ {
            // 发现新岛屿
            if grid[i][j] == '1' {
                islandCount++  // 岛屿数量+1
                exploreIsland(grid, i, j)  // 探索整座岛屿
            }
        }
    }

    return islandCount
}

// 探索整座岛屿的每个角落
func exploreIsland(grid [][]byte, row, col int) {
    // 边界检查
    if row < 0 || row >= len(grid) || 
       col < 0 || col >= len(grid[0]) || 
       grid[row][col] != '1' {
        return
    }

    // 标记已访问（把陆地"淹没"）
    grid[row][col] = '2'  // 或者用'0'，这里用'2'更直观

    // 向四个方向探索
    exploreIsland(grid, row-1, col)  // 上
    exploreIsland(grid, row+1, col)  // 下
    exploreIsland(grid, row, col-1)  // 左
    exploreIsland(grid, row, col+1)  // 右
}

class Solution:
    def numIslands(self, grid: List[List[str]]) -> int:
        if not grid: return 0
        rows, cols = len(grid), len(grid[0])
        count = 0
        def dfs(r, c):
            if r < 0 or r >= rows or c < 0 or c >= cols or grid[r][c] != '1':
                return
            grid[r][c] = '0'
            dfs(r+1, c)
            dfs(r-1, c)
            dfs(r, c+1)
            dfs(r, c-1)
        for i in range(rows):
            for j in range(cols):
                if grid[i][j] == '1':
                    dfs(i, j)
                    count += 1
        return count

class Solution {
    public int numIslands(char[][] grid) {
        if (grid.length == 0) return 0;
        int rows = grid.length, cols = grid[0].length;
        int count = 0;
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                if (grid[i][j] == '1') {
                    dfs(grid, i, j);
                    count++;
                }
            }
        }
        return count;
    }
    private void dfs(char[][] grid, int r, int c) {
        if (r < 0 || r >= grid.length || c < 0 || c >= grid[0].length || grid[r][c] != '1') return;
        grid[r][c] = '0';
        dfs(grid, r+1, c);
        dfs(grid, r-1, c);
        dfs(grid, r, c+1);
        dfs(grid, r, c-1);
    }
}

func orangesRotting(grid [][]int) int {
    rows, cols := len(grid), len(grid[0])
    queue := make([][2]int, 0)
    freshCount := 0  // 新鲜橘子计数

    // 第一步：找到所有腐烂的橘子，入队
    for i := 0; i < rows; i++ {
        for j := 0; j < cols; j++ {
            if grid[i][j] == 2 {
                queue = append(queue, [2]int{i, j})
            } else if grid[i][j] == 1 {
                freshCount++
            }
        }
    }

    // 如果没有新鲜橘子，直接返回0
    if freshCount == 0 {
        return 0
    }

    directions := [4][2]int{{-1, 0}, {1, 0}, {0, -1}, {0, 1}}
    minutes := 0

    // 开始BFS
    for len(queue) > 0 && freshCount > 0 {
        minutes++  // 时间+1
        size := len(queue)  // 当前层的腐烂橘子数

        // 处理当前层的每个腐烂橘子
        for i := 0; i < size; i++ {
            pos := queue[0]
            queue = queue[1:]

            // 向四个方向扩散
            for _, dir := range directions {
                newRow := pos[0] + dir[0]
                newCol := pos[1] + dir[1]

                // 检查边界和是否是新鲜橘子
                if newRow >= 0 && newRow < rows && 
                   newCol >= 0 && newCol < cols && 
                   grid[newRow][newCol] == 1 {

                    grid[newRow][newCol] = 2  // 感染这个橘子
                    queue = append(queue, [2]int{newRow, newCol})
                    freshCount--  // 新鲜橘子-1
                }
            }
        }
    }

    // 如果还有新鲜橘子，返回-1
    if freshCount == 0 {
        return minutes
    }
    return -1
}

class Solution:
    def orangesRotting(self, grid: List[List[int]]) -> int:
        from collections import deque
        rows, cols = len(grid), len(grid[0])
        queue = deque()
        fresh = 0
        for i in range(rows):
            for j in range(cols):
                if grid[i][j] == 2:
                    queue.append((i, j))
                elif grid[i][j] == 1:
                    fresh += 1
        minutes = 0
        while queue and fresh > 0:
            minutes += 1
            for _ in range(len(queue)):
                r, c = queue.popleft()
                for dr, dc in [(1,0), (-1,0), (0,1), (0,-1)]:
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] == 1:
                        grid[nr][nc] = 2
                        fresh -= 1
                        queue.append((nr, nc))
        return minutes if fresh == 0 else -1

class Solution {
    public int orangesRotting(int[][] grid) {
        int rows = grid.length, cols = grid[0].length;
        Queue<int[]> queue = new LinkedList<>();
        int fresh = 0;
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                if (grid[i][j] == 2) queue.offer(new int[]{i, j});
                else if (grid[i][j] == 1) fresh++;
            }
        }
        int minutes = 0;
        int[][] dirs = {{1,0}, {-1,0}, {0,1}, {0,-1}};
        while (!queue.isEmpty() && fresh > 0) {
            minutes++;
            int size = queue.size();
            for (int i = 0; i < size; i++) {
                int[] cell = queue.poll();
                for (int[] d : dirs) {
                    int nr = cell[0] + d[0], nc = cell[1] + d[1];
                    if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && grid[nr][nc] == 1) {
                        grid[nr][nc] = 2;
                        fresh--;
                        queue.offer(new int[]{nr, nc});
                    }
                }
            }
        }
        return fresh == 0 ? minutes : -1;
    }
}

func canFinish(numCourses int, prerequisites [][]int) bool {
    // 构建邻接表：每个课程所指向的后续课程
    adjacency := make([][]int, numCourses)
    for i := range adjacency {
        adjacency[i] = make([]int, 0)
    }

    // 统计每个课程的入度（依赖数量）
    inDegrees := make([]int, numCourses)

    // 填充邻接表和入度数组
    for _, pre := range prerequisites {
        curr := pre[0]  // 当前课程
        prev := pre[1]  // 前置课程
        adjacency[prev] = append(adjacency[prev], curr)  // 添加依赖关系
        inDegrees[curr]++  // 当前课程入度+1
    }

    // 将所有入度为0的课程加入队列
    queue := make([]int, 0)
    for i := 0; i < numCourses; i++ {
        if inDegrees[i] == 0 {
            queue = append(queue, i)
        }
    }

    // BFS遍历
    count := 0  // 记录已学习的课程数
    for len(queue) > 0 {
        course := queue[0]
        queue = queue[1:]
        count++  // 学习一门课程

        // 将当前课程的所有后续课程的入度减1
        for _, next := range adjacency[course] {
            inDegrees[next]--
            // 如果某个后续课程的入度变为0，加入队列
            if inDegrees[next] == 0 {
                queue = append(queue, next)
            }
        }
    }

    // 判断是否学完所有课程
    return count == numCourses
}

class Solution:
    def canFinish(self, numCourses: int, prerequisites: List[List[int]]) -> bool:
        from collections import defaultdict, deque
        graph = defaultdict(list)
        in_degree = [0] * numCourses
        for course, prereq in prerequisites:
            graph[prereq].append(course)
            in_degree[course] += 1
        queue = deque([i for i in range(numCourses) if in_degree[i] == 0])
        count = 0
        while queue:
            course = queue.popleft()
            count += 1
            for next_course in graph[course]:
                in_degree[next_course] -= 1
                if in_degree[next_course] == 0:
                    queue.append(next_course)
        return count == numCourses

class Solution {
    public boolean canFinish(int numCourses, int[][] prerequisites) {
        List<List<Integer>> graph = new ArrayList<>();
        int[] inDegree = new int[numCourses];
        for (int i = 0; i < numCourses; i++) graph.add(new ArrayList<>());
        for (int[] pre : prerequisites) {
            graph.get(pre[1]).add(pre[0]);
            inDegree[pre[0]]++;
        }
        Queue<Integer> queue = new LinkedList<>();
        for (int i = 0; i < numCourses; i++) {
            if (inDegree[i] == 0) queue.offer(i);
        }
        int count = 0;
        while (!queue.isEmpty()) {
            int course = queue.poll();
            count++;
            for (int next : graph.get(course)) {
                if (--inDegree[next] == 0) queue.offer(next);
            }
        }
        return count == numCourses;
    }
}

type TrieNode struct {
    children [26]*TrieNode  // 子节点数组
    isEnd    bool           // 标记是否是单词结尾
}

type Trie struct {
    root *TrieNode  // 根节点
}

func Constructor() Trie {
    return Trie{root: &TrieNode{}}
}

// 插入单词
func (this *Trie) Insert(word string) {
    node := this.root
    for _, c := range word {
        index := int(c - 'a')  // 获取字符对应的索引
        if node.children[index] == nil {
            node.children[index] = &TrieNode{}
        }
        node = node.children[index]
    }
    node.isEnd = true  // 标记单词结尾
}

// 查找单词
func (this *Trie) Search(word string) bool {
    node := this.searchPrefix(word)
    return node != nil && node.isEnd  // 必须完整匹配且是单词结尾
}

// 查找前缀
func (this *Trie) StartsWith(prefix string) bool {
    return this.searchPrefix(prefix) != nil  // 只需要前缀匹配
}

// 查找公共方法
func (this *Trie) searchPrefix(prefix string) *TrieNode {
    node := this.root
    for _, c := range prefix {
        index := int(c - 'a')
        if node.children[index] == nil {
            return nil  // 中途找不到，直接返回nil
        }
        node = node.children[index]
    }
    return node
}

class Trie:
    def __init__(self):
        self.children = {}
        self.is_end = False

    def insert(self, word: str) -> None:
        node = self
        for c in word:
            if c not in node.children:
                node.children[c] = Trie()
            node = node.children[c]
        node.is_end = True

    def search(self, word: str) -> bool:
        node = self
        for c in word:
            if c not in node.children:
                return False
            node = node.children[c]
        return node.is_end

    def startsWith(self, prefix: str) -> bool:
        node = self
        for c in prefix:
            if c not in node.children:
                return False
            node = node.children[c]
        return True

class Trie {
    private TrieNode root;
    public Trie() {
        root = new TrieNode();
    }
    public void insert(String word) {
        TrieNode node = root;
        for (char c : word.toCharArray()) {
            if (!node.children.containsKey(c)) {
                node.children.put(c, new TrieNode());
            }
            node = node.children.get(c);
        }
        node.isEnd = true;
    }
    public boolean search(String word) {
        TrieNode node = root;
        for (char c : word.toCharArray()) {
            if (!node.children.containsKey(c)) return false;
            node = node.children.get(c);
        }
        return node.isEnd;
    }
    public boolean startsWith(String prefix) {
        TrieNode node = root;
        for (char c : prefix.toCharArray()) {
            if (!node.children.containsKey(c)) return false;
            node = node.children.get(c);
        }
        return true;
    }
}
class TrieNode {
    Map<Character, TrieNode> children = new HashMap<>();
    boolean isEnd = false;
}
